#![no_std]          // 不适用标准库
#![no_main]         // 不适用rust语言的main函数

#![feature(alloc_error_handler)]

#[macro_use]        // 引入宏
extern crate alloc;
/* 引入模块 */
mod console;
mod config;
mod drivers;
mod fs;
mod lang_items;
mod mm;
mod sbi;
mod syscall;
mod task;
mod test_runner;
mod timer;
mod trap;
mod input;

use core::arch::global_asm;             // 引入汇编文件
global_asm!(include_str!("entry.asm")); // 引入entry.asm文件

fn clear_bss() {
    extern "C" {
        fn sbss();
        fn ebss();
    }
    unsafe {
        core::slice::from_raw_parts_mut(
            sbss as usize as *mut u8,
            ebss as usize - sbss as usize,
        )
        .fill(0);
    }
}

#[unsafe(no_mangle)]
pub fn rust_main() -> ! {
    clear_bss();
    // 初始化 log 系统
    console::log_init();
    println!("[kernel] HPU OS starting...");

    // 内存初始化
    mm::init();

    // 记录 TRAMPOLINE 物理地址（__alltraps 所在页）
    extern "C" { fn __alltraps(); }
    unsafe {
        config::TRAMPOLINE_PA = __alltraps as usize;
    }

    // 中断初始化
    trap::init();

    // 设置首次时钟中断
    timer::set_next_trigger();

    // The contest test image is exposed as a legacy virtio-mmio block device.
    // It must be initialized before fs::init probes the EXT4 superblock.
    drivers::init();

    // 初始化文件系统（评测环境会挂载 EXT4 磁盘）
    fs::init();

    // 评测模式：扫描 EXT4 磁盘并运行测试程序
    // Keep the existing direct basic runner and let it advance into the
    // remaining contest groups. Local bring-up still has an embedded init.
    if !test_runner::start_from_disk() {
        crate::println!("[testsuite] no supported test image, shutting down");
        crate::sbi::shutdown(false);
    }

    // 进入调度循环
    task::run_tasks();
}

/// 评测模式：从 EXT4 磁盘扫描并运行测试程序
fn run_testsuite() {
    use crate::fs::manager::FS_MANAGER;
    use crate::fs::ext4;

    let mgr = FS_MANAGER.lock();
    let fs_ref = match mgr.as_ref() {
        Some(m) => &m.fs,
        None => {
            drop(mgr);
            // 无磁盘，回退到嵌入式 initproc
            crate::println!("[testsuite] No EXT4 disk found, falling back to embedded initproc");
            run_init();
            return;
        }
    };

    // 扫描根目录
    let entries = ext4::list_root_dir(fs_ref);
    crate::println!("[testsuite] Found {} entries in root", entries.len());

    // 过滤出常规文件
    let mut test_files: alloc::vec::Vec<(alloc::vec::Vec<u8>, u32, usize)> = alloc::vec::Vec::new();
    for (inode_no, name) in &entries {
        if let Ok(stat) = fs_ref.stat_inode(*inode_no) {
            if stat.is_file {
                let name_str = core::str::from_utf8(name).unwrap_or("???");
                crate::println!("[testsuite]   {} (inode={}, {} bytes)", name_str, inode_no, stat.size);
                test_files.push((name.clone(), *inode_no, stat.size));
            }
        }
    }
    drop(mgr);

    if test_files.is_empty() {
        crate::println!("[testsuite] No test files on disk, falling back to embedded initproc");
        run_init();
        return;
    }

    // 依次执行每个测试程序
    for (name, inode_no, size) in &test_files {
        let name_str = core::str::from_utf8(name).unwrap_or("???");
        crate::println!("\n#### OS COMP TEST GROUP START {} ####", name_str);

        // 从 EXT4 读取文件内容
        let mgr = FS_MANAGER.lock();
        let fs_ref = &mgr.as_ref().unwrap().fs;
        let inode = match fs_ref.stat_inode(*inode_no) {
            Ok(ino) => ino,
            Err(_) => {
                crate::println!("[testsuite] Failed to stat inode {}", inode_no);
                drop(mgr);
                crate::println!("#### OS COMP TEST GROUP END {} ####", name_str);
                continue;
            }
        };

        let mut elf_data = alloc::vec![0u8; *size];
        match fs_ref.read_file(&inode, 0, &mut elf_data) {
            Ok(n) => {
                crate::println!("[testsuite] Read {} bytes from {}", n, name_str);
                elf_data.truncate(n);
            }
            Err(_) => {
                crate::println!("[testsuite] Failed to read {}", name_str);
                drop(mgr);
                crate::println!("#### OS COMP TEST GROUP END {} ####", name_str);
                continue;
            }
        }
        drop(mgr);

        // 创建任务并加入调度
        let task = alloc::sync::Arc::new(task::TaskControlBlock::new(&elf_data));
        task::add_task(task);
        // 让调度器运行此任务（简化：依赖调度循环自动执行）
        crate::println!("[testsuite] Queued {}", name_str);

        crate::println!("#### OS COMP TEST GROUP END {} ####", name_str);
    }

    // 所有测试排队完成，关闭系统
    crate::println!("[testsuite] All tests queued, shutting down.");
    crate::sbi::shutdown(false);
}

/// 加载嵌入式 ELF 作为 init 进程（回退模式）
fn run_init() {
    // 嵌入用户程序 ELF
    let elf_data = include_bytes!("../user/target/riscv64gc-unknown-none-elf/release/user");
    println!("[kernel] Loading initproc ({} bytes)...", elf_data.len());

    // 创建第一个用户进程
    let task = alloc::sync::Arc::new(task::TaskControlBlock::new(elf_data));
    task::add_task(task);
    println!("[kernel] Initproc added to scheduler.");
}

/// 分配错误处理
#[alloc_error_handler]
fn alloc_error_handler(layout: core::alloc::Layout) -> ! {
    panic!("Allocation error: {:?}", layout);
}

//! 内核配置常量 — 地址空间布局等

pub const PAGE_SIZE: usize = 0x1000;
pub const PAGE_SIZE_BITS: usize = 0xc;

pub const TASK_SIZE: usize = 0xc000_0000;
pub const USER_STACK_BASE: usize = TASK_SIZE - PAGE_SIZE;  // 0xBFFFF000
pub const USER_STACK_SIZE: usize = PAGE_SIZE * 40;
pub const USER_HEAP_SIZE: usize = PAGE_SIZE * 20;

pub const MMAP_BASE: usize = 0x6000_0000;
pub const MMAP_END: usize = 0x8000_0000;

// 内核堆大小
pub const KERNEL_HEAP_SIZE: usize = PAGE_SIZE * 0x100;

// 用户地址空间最高页 — TRAMPOLINE（存放 __alltraps/__restore）
pub const TRAMPOLINE: usize = usize::MAX - PAGE_SIZE + 1;   // 0xFFFFFFFFFFFFF000
// TRAP_CONTEXT 放在 TRAMPOLINE 下一页
pub const TRAP_CONTEXT_BASE: usize = TRAMPOLINE - PAGE_SIZE; // 0xFFFFFFFFFFFFE000

// 物理内存范围（QEMU virt 默认 128MB）
pub const MEMORY_START: usize = 0x8000_0000;
// The grader starts QEMU with 128 MiB.  The original 9.8 MiB arena is not
// enough for BusyBox, a shell and benchmark children at the same time.
pub const MEMORY_END: usize = 0x8800_0000;

pub const CLOCK_FREQ: usize = 100_000_000;
pub const TIMER_INTERVAL: usize = 5_000_000;

// 由链接脚本定义的 strampoline 地址，在 mm::init 后设置
pub static mut TRAMPOLINE_PA: usize = 0;

pub const SYSTEM_TASK_LIMIT: usize = 128;
pub const SYSTEM_FD_LIMIT: usize = 256;
pub const RLIMIT_COUNT: usize = 16;
pub const RLIMIT_NPROC: usize = 6;
pub const RLIMIT_NOFILE: usize = 7;

/* 链接脚本：控制内核映像在内存中的布局 */
OUTPUT_ARCH(riscv)          /* 指定目标架构为 RISC-V */
ENTRY(_start)              /* 程序入口点符号，启动汇编代码从这里开始执行 */
BASE_ADDRESS = 0x80200000; /* 内核镜像的基址，内核从这个地址开始加载 */

SECTIONS
{
    . = BASE_ADDRESS;    /* 当前地址指针设置为基址 */
    skernel = .;         /* 定义内核开始地址符号 skernel */

    stext = .;           /* 定义代码段开始地址符号 stext */
    .text : {            /* .text 段，存放可执行代码 */
        *(.text.entry)   /* 入口代码段，比如 startup 或 _start */
        *(.text .text.*) /* 其他所有 .text 节中的代码 */
    }

    . = ALIGN(4K);       /* trampoline 单独占一页 */
    strampoline = .;
    .trampoline : {
        *(.text.trampoline)
    }
    . = ALIGN(4K);

    . = ALIGN(4K);       /* 将下一个段对齐到 4KB 边界 */
    etext = .;           /* 代码段结束地址符号 etext */
    srodata = .;         /* 只读数据段开始地址符号 srodata */
    .rodata : {          /* .rodata 段，存放只读数据常量 */
        *(.rodata .rodata.*)
        *(.srodata .srodata.*)
    }

    . = ALIGN(4K);       /* 对齐到下一页，方便内存管理 */
    erodata = .;         /* 只读数据段结束地址符号 erodata */
    sdata = .;           /* 已初始化数据段开始地址符号 sdata */
    .data : {            /* .data 段，存放已初始化的全局/静态变量 */
        *(.data .data.*)
        *(.sdata .sdata.*)
    }

    . = ALIGN(4K);       /* 再次对齐，保证 .bss 段页对齐 */
    edata = .;           /* 已初始化数据段结束地址符号 edata */
    .bss : {
        *(.bss.stack)
        sbss = .;        /* bss 段开始地址符号 sbss */
        *(.bss .bss.*)
        *(.sbss .sbss.*)
    }

    . = ALIGN(4K);       /* .bss 段结束后再次对齐 */
    ebss = .;            /* bss 段结束地址符号 ebss */

    /* 预留页表空间 — 扩大 ekernel 使 OpenSBI 映射更多物理内存 */
    . = ALIGN(4K);
    .pt_reserve (NOLOAD) : {
        . += 0x80000;    /* 512KB 预留给内核初始页表 */
    }
    ekernel = .;         /* 内核镜像结束地址符号 ekernel */

    /DISCARD/ : {        /* 不放入最终镜像的节 */
        *(.eh_frame)     /* 异常处理/栈展开信息，对内核通常不需要 */
    }
}

/* SBI函数 */
#[allow(deprecated)]
pub fn console_getchar() -> Option<char> {      // 获取输入字符，无输入返回 None
    let ret = sbi_rt::legacy::console_getchar();
    if ret == usize::MAX {                      // -1 表示无输入
        None
    } else {
        Some((ret & 0xFF) as u8 as char)        // 取低8位转为字符
    }
}
