    #[allow(deprecated)]
    sbi_rt::legacy::shutdown();
    unreachable!()
}

use crate::sbi::console_putchar;            // 使用sbi模块中的console_putchar函数
use core::fmt::{self, Write};               // 引入core库中的fmt模块和Write trait

struct Stdout;                              // 创建结构体Stdout,作为标准输出的实现

impl Write for Stdout {                     // 赋予Stdout Write trait
    fn write_str(&mut self, s: &str) -> fmt::Result {   // 创建write_str函数,输出字符串s中的每个字符
        for c in s.chars() {
            console_putchar(c as usize);
        }
        Ok(())                                         // 返回Ok(())
    }
}

pub fn print(args: fmt::Arguments) {        // public函数print,接受fmt::Arguments类型的参数args
    Stdout.write_fmt(args).unwrap();        // 使用Stdout的write_fmt输出args,如果输出失败则调用unwrap()
}

#[macro_export]                             // 导出宏
macro_rules! print {                        // 定义print宏,接受一个格式字符串和可选的参数
    ($fmt: literal $(, $($arg: tt)+)?) => {
        $crate::console::print(format_args!($fmt $(, $($arg)+)?));  // 格式化输出
    }
}

#[macro_export]                             // 导出宏
macro_rules! println {                      // 定义println宏,接受一个格式字符串和可选的参数
    ($fmt: literal $(, $($arg: tt)+)?) => {
        $crate::console::print(format_args!(concat!($fmt, "\n") $(, $($arg)+)?));   //格式化输出
    }
}

/// 简单的 log 初始化（使 log crate 输出到 println）
pub fn log_init() {
    static LOGGER: SimpleLogger = SimpleLogger;
    log::set_logger(&LOGGER).unwrap();
    log::set_max_level(log::LevelFilter::Info);
}

struct SimpleLogger;

impl log::Log for SimpleLogger {
    fn enabled(&self, _metadata: &log::Metadata) -> bool { true }

    fn log(&self, record: &log::Record) {
        print(format_args!(
            "[{:<5}] {}\n",
            record.level(),
            record.args()
        ));
    }

    fn flush(&self) {}
}

use crate::config::TIMER_INTERVAL;


pub fn set_next_trigger() {             // 设置下一次时钟中断
    let time = get_time();
    set_timer(time + TIMER_INTERVAL);
}

pub fn get_time() -> usize {              // 读取当前时钟的值                // 读取当前时钟的值
    let ret: usize;
    unsafe {
        core::arch::asm!("rdtime {0}", out(reg) ret);
    }
    ret
}

fn set_timer(stime_value: usize) {      // 设置时钟
    unsafe {
        core::arch::asm!(
            "li a7, 0",
            "ecall",
            in("a0") stime_value,
        );
    }
}

#[repr(C)]
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
pub struct TimeVal {
    pub sec: usize,
    pub usec: usize,
}

impl TimeVal {
    pub fn new() -> Self {
        Self { sec: 0, usec: 0 }
    }
    pub fn now() -> Self {
        let t = get_time();
        let sec = t / crate::config::CLOCK_FREQ;
        let usec = (t % crate::config::CLOCK_FREQ) * 1_000_000 / crate::config::CLOCK_FREQ;
        Self { sec, usec }
    }
}

#[repr(C)]
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
pub struct TimeSpec {
    pub sec: usize,
    pub nsec: usize,
}

impl TimeSpec {
    pub fn new() -> Self {
        Self { sec: 0, nsec: 0 }
    }
    pub fn now() -> Self {
        let t = get_time();
        let sec = t / crate::config::CLOCK_FREQ;
        let nsec = (t % crate::config::CLOCK_FREQ) * 1_000_000_000 / crate::config::CLOCK_FREQ;
        Self { sec, nsec }
    }
}

impl core::ops::Add<&TimeSpec> for TimeSpec {
    type Output = Self;
    fn add(self, rhs: &Self) -> Self {
        let mut sec = self.sec + rhs.sec;
        let mut nsec = self.nsec + rhs.nsec;
        if nsec >= 1_000_000_000 {
            sec += 1;
            nsec -= 1_000_000_000;
        }
        Self { sec, nsec }
    }
}

impl core::ops::Sub<Self> for TimeSpec {
    type Output = Self;
    fn sub(self, rhs: Self) -> Self {
        if self >= rhs {
            let mut sec = self.sec - rhs.sec;
            let mut nsec;
            if self.nsec >= rhs.nsec {
                nsec = self.nsec - rhs.nsec;
            } else {
                sec -= 1;
                nsec = self.nsec + 1_000_000_000 - rhs.nsec;
            }
            Self { sec, nsec }
        } else {
            Self { sec: 0, nsec: 0 }
        }
    }
}

use crate::sbi::shutdown;
use core::panic::PanicInfo;

#[panic_handler]                                // 定义panic处理函数
fn panic(info: &PanicInfo) -> ! {               // 接受PanicInfo类型的info，永不返回
    let message = info.message();               // 获取info中的message
    if let Some(location) = info.location() {   // 匹配location,如果存在则获取文件名和行号
        crate::console::print(format_args!(     // 输出panic信息
            "Panicked at {}:{} {}\n",
            location.file(),                    // 文件名
            location.line(),                    // 行号
            message                             // message
        ));
    } else {                                    // 反之则输出message
        crate::console::print(format_args!("Panicked: {}\n", message));
    }
    shutdown(true)                              // 关机(因panic关机)
}

/* 输入输出函数 */
use crate::{print, println};
use crate::sbi;                         // 引入sbi模块，使用其中的console_getchar和console_putchar函数
use crate::trap;

/* 输入输出函数 */
// 该函数实现了在屏幕上打印输入字符，用户按下ESC键时推出，实现了简单的人机交互
pub fn what_you_type() -> ! {           // 永不返回的函数，需要panic处理
    println!("Press keys (ESC to exit)...");
    loop {
        if let Some(c) = sbi::console_getchar() {      // Some为输入字符，相当于一个Option类型的匹配，None表示没有输入
        // if let 用于检查右值是否匹配Some(c)，如果匹配成功则将c绑定到输入的字符上，并执行循环体内的代码        
            if c as u8 == 27 {                         // ESC 键 (ASCII 27) 退出
                println!("\nBye!");
                break;
            }
            sbi::console_putchar(c as usize);          // 回显输入的字符
        }
    }
    panic!("Shutdown machine!");                       // panic处理
}

/* 获取字符 */
// 该函数实现了堵塞式获取输入字符，只有当用户输入一个字符时才返回，适用于需要等待用户输入的场景
pub fn getchar() -> char{
    loop{
        if let Some(c) = sbi::console_getchar() {
            return c as char;
        }
    }
}

/* 读取一行输入 */
// 该函数实现了读取一整行的输入，为shell的实现提供了基础
pub fn read_line(buffer: &mut [u8]) -> usize {
    let mut idx: usize = 0;
    loop{
        if let Some(c) = sbi::console_getchar() {          // 获取输入
            if c as u8 == 10 || c as u8 == 13 {            // 换行符 (LF) 或回车符 (CR) 结束输入
                sbi::console_putchar(b'\n' as usize);
                break;
            }
            if c as u8 == 0x7F || c as u8 == 0x08 {        // 删除功能，支持Backspace和Delete键
                if idx > 0 {
                    idx -= 1;
                    sbi::console_putchar(0x08 as usize);   // 光标后退
                    sbi::console_putchar(b' ' as usize);   // 打印空格覆盖
                    sbi::console_putchar(0x08 as usize);   // 光标再后退
                }
            } else if idx < buffer.len() {                 // 普通字符
                buffer[idx] = c as u8;
                sbi::console_putchar(c as usize);          // 回显输入的字符
                idx += 1;
            }
        }
    }
    idx
}

/* 交互式 shell */
// 该函数实现了一个简单的shell，用户可以通过输入命令获得相应的信息
pub fn shell() -> ! {
    loop {
        print!("HPU> ");                            // 打印提示符
        let mut buf = [0u8; 64];
        let len = read_line(&mut buf);
        match &buf[..len] {                         // 匹配输入的命令
            b"help" => println!("Available commands: help, echo, mm, task, stop, interrupt, intoff, shutdown"),
            b"echo" => println!("Echo: {}", core::str::from_utf8(&buf[..len]).unwrap_or("Invalid UTF-8")),
            b"shutdown" => {
                println!("Shutting down...");
                sbi::shutdown(true);                // 关机
            }
            b"mm" => {
                crate::mm::info();
                println!("Memory test done.");
            }
            b"task" => {
               trap::init();
               println!("Task mode not available in this version.");
            }
            b"stop" => {
                println!("Task stop not available in this version.");
            }
            b"interrupt" => {
                println!("Enabling interrupt...");
                trap::init();
            }
            b"intoff" => {
                unsafe { riscv::register::sstatus::clear_sie(); }       // 将SIE(Supervisor Interrupt Enable)清零，从而达到关闭中断的效果
                println!("Interrupts disabled.");
            }
            _ => println!("Unknown command. Type 'help' for available commands."),  // 其他输入则提示未知命令
        }
    }
}

//! 内存管理模块 — 页表、帧分配器、堆分配器、地址空间
use crate::{print, println};
mod address;
mod heap_allocator;
mod frame_allocator;
mod page_table;
mod memory_set;

pub use address::{PhysAddr, PhysPageNum, VirtAddr, VirtPageNum, VPNRange, StepByOne};
pub use frame_allocator::{frame_alloc, frame_dealloc, FrameTracker};
pub use memory_set::{
    check_valid_va, translated_byte_buffer, translated_refmut, translated_str, virt_to_phys,
    MemorySet, UserBuffer,
};
pub use page_table::{PageTable, PageTableEntry, PTEFlags};
pub use memory_set::{MapPermission, KERNEL_SPACE};

pub fn init() {
    heap_allocator::init_heap();
    let kernel_end = unsafe {
        extern "C" {
            fn ekernel();
        }
        ekernel as usize
    };
    // 从内核段内部开始分配，防止 Drop 导致页表帧被回收
    let frame_start =
        (kernel_end + crate::config::PAGE_SIZE - 1) & !(crate::config::PAGE_SIZE - 1);
    frame_allocator::init_frame_allocator(frame_start, crate::config::MEMORY_END);

    // 创建并激活内核地址空间
    let kernel_space = memory_set::MemorySet::new_kernel();
    kernel_space.activate();
    // 防止 kernel_space 被 Drop——页表帧必须永久存活
    core::mem::forget(kernel_space);
    println!("[mm] Kernel memory space activated!");
}

pub fn info() {
    println!("[mm] Testing frame allocator...");
    if let Some(frame) = frame_allocator::frame_alloc() {
        println!("[mm] Allocated frame: PPN={:#x}", frame.ppn.0);
    }
    println!("[mm] Frame allocator works!");
    if let Some(mut pt) = page_table::PageTable::new() {
        println!("[mm] Page table created, root PPN={:#x}", pt.token() & 0xfffffffffff);
        println!("[mm] Page table works!");
    } else {
        println!("[mm] Page table creation failed!");
    }
}

use core::fmt::{self, Debug, Formatter};


#[derive(Copy, Clone, Ord, PartialOrd, Eq, PartialEq)]
pub struct PhysAddr(pub usize);

#[derive(Copy, Clone, Ord, PartialOrd, Eq, PartialEq)]
pub struct VirtAddr(pub usize);

#[derive(Copy, Clone, Ord, PartialOrd, Eq, PartialEq)]
pub struct PhysPageNum(pub usize);

#[derive(Copy, Clone, Ord, PartialOrd, Eq, PartialEq)]
pub struct VirtPageNum(pub usize);

// 常量
pub const PAGE_SIZE: usize = 0x1000;
pub const PAGE_SIZE_BITS: usize = 12;

// ---- 地址换算 ----
impl PhysAddr {
    pub fn page_offset(&self) -> usize { self.0 & (PAGE_SIZE - 1) }
    pub fn floor(&self) -> PhysPageNum { PhysPageNum(self.0 / PAGE_SIZE) }
    pub fn ceil(&self) -> PhysPageNum {
        if self.page_offset() == 0 {
            PhysPageNum(self.0 / PAGE_SIZE)
        } else {
            PhysPageNum(self.0 / PAGE_SIZE + 1)
        }
    }
}
impl From<PhysAddr> for usize { fn from(v: PhysAddr) -> Self { v.0 } }
impl From<usize> for PhysAddr { fn from(v: usize) -> Self { Self(v) } }

impl VirtAddr {
    pub fn page_offset(&self) -> usize { self.0 & (PAGE_SIZE - 1) }
    pub fn floor(&self) -> VirtPageNum { VirtPageNum(self.0 / PAGE_SIZE) }
    pub fn ceil(&self) -> VirtPageNum {
        if self.page_offset() == 0 {
            VirtPageNum(self.0 / PAGE_SIZE)
        } else {
            VirtPageNum(self.0 / PAGE_SIZE + 1)
        }
    }
}
impl From<VirtAddr> for usize { fn from(v: VirtAddr) -> Self { v.0 } }
impl From<usize> for VirtAddr { fn from(v: usize) -> Self { Self(v) } }

impl PhysPageNum {
    pub fn get_addr(&self) -> PhysAddr { PhysAddr(self.0 * PAGE_SIZE) }
}
impl From<PhysPageNum> for usize { fn from(v: PhysPageNum) -> Self { v.0 } }
impl From<usize> for PhysPageNum { fn from(v: usize) -> Self { Self(v) } }

impl VirtPageNum {
    pub fn get_addr(&self) -> VirtAddr { VirtAddr(self.0 * PAGE_SIZE) }
}
impl From<VirtPageNum> for usize { fn from(v: VirtPageNum) -> Self { v.0 } }
impl From<usize> for VirtPageNum { fn from(v: usize) -> Self { Self(v) } }

/// VPN 范围迭代器
pub struct VPNRange {
    start: VirtPageNum,
    end: VirtPageNum,
}
impl VPNRange {
    pub fn new(start: VirtPageNum, end: VirtPageNum) -> Self {
        Self { start, end }
    }
}
impl Iterator for VPNRange {
    type Item = VirtPageNum;
    fn next(&mut self) -> Option<Self::Item> {
        if self.start < self.end {
            let vpn = self.start;
            self.start.0 += 1;
            Some(vpn)
        } else {
            None
        }
    }
}

/// 步进 trait
pub trait StepByOne {
    fn step(&mut self);
}
impl StepByOne for VirtPageNum {
    fn step(&mut self) { self.0 += 1; }
}

impl Debug for PhysAddr {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        f.write_fmt(format_args!("PA:{:#x}", self.0))
    }
}
impl Debug for PhysPageNum {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        f.write_fmt(format_args!("PPN:{:#x}", self.0))
    }
}
impl Debug for VirtAddr {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        f.write_fmt(format_args!("VA:{:#x}", self.0))
    }
}
impl Debug for VirtPageNum {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        f.write_fmt(format_args!("VPN:{:#x}", self.0))
    }
}

use bitflags::*;
use crate::mm::address::{PhysAddr, PhysPageNum, VirtAddr, VirtPageNum};
use crate::mm::frame_allocator::{frame_alloc, frame_dealloc, FrameTracker};
use alloc::vec::Vec;

bitflags! {                 // 标志位库
    #[derive(Copy, Clone)]
    pub struct PTEFlags: u8 {
        const V = 1 << 0;   // Valid
        const R = 1 << 1;   // Readable
        const W = 1 << 2;   // Writable
        const X = 1 << 3;   // Executable
        const U = 1 << 4;   // User
        const G = 1 << 5;   // Global
        const A = 1 << 6;   // Accessed
        const D = 1 << 7;   // Dirty
    }
}

#[derive(Copy, Clone)]          // 给这个结构体自动生成“复制”和“克隆”，方便PTE的读写
pub struct PageTableEntry {
    pub bits: usize,
}

impl PageTableEntry {           // PTE 的方法：创建、读取、判断
    pub fn new(ppn: PhysPageNum, flags: PTEFlags) -> Self { // 创建PTE
        Self { bits: ppn.0 << 10 | flags.bits() as usize } 
    }
    pub fn empty() -> Self {Self { bits: 0 }}   // 清空PTE
    pub fn ppn(&self) -> PhysPageNum { ((self.bits >> 10) & 0xfffffffffff).into() }     // 读取PPN
    pub fn flags(&self) -> PTEFlags { PTEFlags::from_bits(self.bits as u8).unwrap() }   // 读取标志位，后八位所以用as u8，.unwrap()表明"有值就取出值，没值就 panic 崩溃"
    pub fn is_valid(&self) -> bool { self.bits & 1 != 0}
}

pub struct PageTable {          // 建立页表结构体
    root_ppn: PhysPageNum,      // 根物理地址
    frames: Vec<FrameTracker>,  // 持有所有中间页表的物理页，防止被回收
}

fn vpn_index(vaddr: VirtAddr, level: usize) ->usize {   // 从虚拟地址提取某级的索引，& 0x1ff取低9位
    (vaddr.0 >> (12 + level * 9)) & 0x1ff               // bits: 38-30    29-21     20-12     11-0
                                                        //       VPN[2]    VPN[1]    VPN[0]    偏移
}
/* 以上代码为RISC-V内核共通的，后面直接复制粘贴就行 */

fn ppn_to_ptes(ppn: PhysPageNum) -> &'static mut [PageTableEntry] { // 物理页号→PTE数组
    let pa: usize = ppn.0 * 0x1000;                                 // PPN → 物理地址。第N页的起始地址 = N * 4096
    unsafe { core::slice::from_raw_parts_mut(pa as *mut PageTableEntry, 512) }
    // 把物理地址当作 512 个 PTE 的数组来读写
}

impl PageTable {
    /// 创建一个新的空页表
    pub fn new() -> Option<Self> {
        let frame = frame_alloc()?;                              // 分配一页作为根页表
        let root_ppn = frame.ppn;                                // 将新分配的一页作为根页表
        Some(Self { root_ppn, frames: vec![frame] })             // 创建PageTable结构体，用Some包起来
    }

    /// 遍历页表找到 vaddr 对应的 PTE，没有中间表就自动创建
    pub fn empty() -> Self {
        Self { root_ppn: PhysPageNum(0), frames: Vec::new() }
    }

    fn find_pte_create(&mut self, vaddr: VirtAddr) -> &mut PageTableEntry {
        let mut current_ppn = self.root_ppn;                     // 从根页表开始

        for level in (0..3).rev() {                              // level = 2, 1, 0
            let ptes = ppn_to_ptes(current_ppn);                 // 当前页表
            let idx = vpn_index(vaddr, level);                   // 当前级的索引
            let entry = &mut ptes[idx];                          // 对应的 PTE

            if level == 0 {
                return entry;                                    // 最后一级 → 直接返回 PTE
            }

            if !entry.is_valid() {
                // 中间级表不存在 → 分配一个新页表
                let new_frame = frame_alloc().expect("OOM");     // .expect("OOM")表示如果取出来是None就panic并打印"OOM"(Out Of Memory)
                let new_ppn = new_frame.ppn;
                self.frames.push(new_frame);                     // 记入 frames 防止被回收
                *entry = PageTableEntry::new(new_ppn, PTEFlags::V); // 写入 PTE
                current_ppn = new_ppn;
            } else {
                current_ppn = entry.ppn();                       // 进入下一级
            }
        }
        unreachable!()                                           // 表示这行代码永远跑不到，因为for循环里当level = 0时一定会return，不可能正常退出循环。但编译器不知道“一定return”这件事，unreachable!()就是用来满足编译器的："这里放个占位符，实际上跑不到"
    }

    /// 建立虚拟地址到物理页的映射
    pub fn map(&mut self, vaddr: VirtAddr, ppn: PhysPageNum, flags: PTEFlags) {
        let entry = self.find_pte_create(vaddr);                 // 通过调用find_pte_create()获取PTE(PageTableEntry)
        *entry = PageTableEntry::new(ppn, flags | PTEFlags::V);  // 设置 PTE（自动加上 V 标志）
    }

    /// 解除虚拟地址的映射
    pub fn unmap(&mut self, vaddr: VirtAddr) {
        let entry = self.find_pte_create(vaddr);
        *entry = PageTableEntry::empty();
    }

    pub fn unmap_if_mapped(&mut self, vaddr: VirtAddr) {
        if let Some(entry) = self.find_pte_mut(vaddr) {
            *entry = PageTableEntry::empty();
        }
    }

    pub fn set_flags_if_mapped(&mut self, vaddr: VirtAddr, flags: PTEFlags) -> bool {
        if let Some(entry) = self.find_pte_mut(vaddr) {
            let ppn = entry.ppn();
            *entry = PageTableEntry::new(ppn, flags | PTEFlags::V);
            true
        } else {
            false
        }
    }

    /// 从已有的 satp token 恢复页表（用于查询）
    pub fn from_token(token: usize) -> Self {
        let root_ppn = PhysPageNum(token & 0xfffffffffff);
        Self { root_ppn, frames: Vec::new() }
    }

    /// 只查找 PTE，不创建中间表（用于 virt_to_phys）
    pub fn find_pte(&self, vaddr: VirtAddr) -> Option<PageTableEntry> {
        let mut current_ppn = self.root_ppn;
        for level in (0..3).rev() {
            let ptes = ppn_to_ptes(current_ppn);
            let idx = vpn_index(vaddr, level);
            let entry = &ptes[idx];
            if level == 0 { return Some(*entry); }
            if !entry.is_valid() { return None; }
            current_ppn = entry.ppn();
        }
        None
    }

    fn find_pte_mut(&mut self, vaddr: VirtAddr) -> Option<&'static mut PageTableEntry> {
        let mut current_ppn = self.root_ppn;
        for level in (0..3).rev() {
            let ptes = ppn_to_ptes(current_ppn);
            let idx = vpn_index(vaddr, level);
            let entry = &mut ptes[idx];
            if level == 0 {
                return if entry.is_valid() { Some(entry) } else { None };
            }
            if !entry.is_valid() {
                return None;
            }
            current_ppn = entry.ppn();
        }
        None
    }

    /// 生成写入 satp CSR 的值
    pub fn token(&self) -> usize {
        8usize << 60 | self.root_ppn.0
    }
}

use lazy_static::*;
use crate::mm::address::PhysPageNum;    // 引入PhysPageNum（物理页号包装）
use spin::Mutex;                        // 添加互斥机制
use alloc::vec::Vec;                    // 引入Vec类型（用于存回收的页码列表）

pub struct FrameTracker {               // 创建物理页码
    pub ppn: PhysPageNum,               // ppn为变量名类型是usize，PhysPageNum是类型名
}

impl FrameTracker {
    pub fn new(ppn: PhysPageNum) -> Self {      // 接受PhysPageNum类型的变量，返回值是FrameTracker类型（Self为简写）
        let ptr = ppn.0 * 0x1000;               // 分配物理地址
        unsafe {
            core::ptr::write_bytes(ptr as *mut u8, 0, 0x1000);  // 先写0
        }
        Self { ppn }                            // 返回ppn
    }
}

impl Drop for FrameTracker {                    // 为FrameTracker添加Drop函数，目的是删除某页
    fn drop(&mut self) {
        frame_dealloc(self.ppn);
    }
}

struct FrameAllocator {                         // 创建结构体管理页
    start: usize,
    current: usize,                             // 目前地址
    end: usize,                                 // 末地址
    recycled: Vec<usize>,                       // 已回收的地址
}

impl FrameAllocator {                           // 创建分配函数
    fn new() ->Self {                           // 新建空白页
        Self { start: 0, current: 0, end: 0, recycled: Vec::new() }
    }

    fn alloc(&mut self) ->Option<FrameTracker> {    // 分配函数，Option表示可能借到一页，也可能没页可借了
        if let Some(ppn) = self.recycled.pop() {    // 如果有已回收的页则分配至已回收的空间
            return Some(FrameTracker::new(PhysPageNum(ppn)));
        }
        if self.current < self.end {                // 如果有足够的空间
            let ppn = self.current;
            self.current += 1;
            return Some(FrameTracker::new(PhysPageNum(ppn)));
        }
        None                                        // 什么都不满足，那就None
    }

    fn dealloc(&mut self, ppn: PhysPageNum) {        // 删除页
        self.recycled.push(ppn.0);
    }
}

lazy_static! {
    static ref FRAME_ALLOCATOR: Mutex<FrameAllocator> = Mutex::new(FrameAllocator::new());
}                                                           // 创建一个带有互锁机制的页分配器

pub fn init_frame_allocator(start: usize, end: usize) {     // 初始化页分配器
    let mut allocator = FRAME_ALLOCATOR.lock();             // 锁住因为会有多个进程使用
    allocator.start = start / 0x1000;
    allocator.current = start / 0x1000;                     // 赋予目前地址
    allocator.end = end / 0x1000;                           // 赋予末地址
}

pub fn frame_alloc() -> Option<FrameTracker> {              // 分配页
    FRAME_ALLOCATOR.lock().alloc()
}

pub fn frame_dealloc(ppn: PhysPageNum) {                    // 删除页
    FRAME_ALLOCATOR.lock().dealloc(ppn)
}

pub fn frame_allocator_stats() -> (usize, usize, usize, usize) {
    let allocator = FRAME_ALLOCATOR.lock();
    let total = allocator.end.saturating_sub(allocator.start);
    let fresh = allocator.end.saturating_sub(allocator.current);
    let recycled = allocator.recycled.len();
    let used = total.saturating_sub(fresh + recycled);
    (used, fresh, recycled, total)
}

use buddy_system_allocator::LockedHeap;                     // 引入第三方库，该库实现了一个成熟的内核堆分配器——“伙伴算法”

// Test executables are buffered in kernel memory before they are mapped.
const HEAP_SIZE: usize = 16 * 1024 * 1024;

static mut HEAP_SPACE: [u8; HEAP_SIZE] = [0; HEAP_SIZE];    // 在内存中划一块64KB的数组，初值皆为0

#[global_allocator]             // 全局堆分配器 #[global_allocator]告诉编译器，以后所有Box::new等内存分配操作，都用这个分配器
static HEAP_ALLOCATOR: LockedHeap<32> = LockedHeap::empty();

pub fn init_heap() {            // 初始化堆 使用.lock()加锁管理内存
    unsafe {
        HEAP_ALLOCATOR.lock().init(
            core::ptr::addr_of_mut!(HEAP_SPACE) as usize,
            HEAP_SIZE);
    }
}

use crate::mm::address::{PhysAddr, PhysPageNum, VirtAddr, VirtPageNum, VPNRange};
use crate::mm::page_table::{PTEFlags, PageTableEntry, PageTable};
use crate::mm::frame_allocator::{frame_alloc, FrameTracker};
use crate::config::TRAMPOLINE;
use alloc::vec::Vec;
use riscv::register::satp;
use core::fmt::{self, Debug, Formatter};

/// 从链接脚本读取符号地址
macro_rules! link_symbol {
    ($name:ident) => {{
        #[unsafe(no_mangle)]
        unsafe extern "C" { static $name: u8; }
        unsafe { &$name as *const u8 as usize }
    }};
}

/// 页表权限（包含 U 位）
pub type MapPermission = PTEFlags;

/// 映射区域：记录一段连续虚拟地址的映射
#[derive(Clone)]
pub struct MapArea {
    vaddr: usize,
    pages: usize,
    flags: PTEFlags,
}

/// 地址空间
pub struct MemorySet {
    pub page_table: PageTable,
    pub areas: Vec<MapArea>,
    pub frames: Vec<FrameTracker>,  // 持有所有分配页的引用
}

impl MemorySet {
    /// 创建并激活内核地址空间
    pub fn new_kernel() -> Self {
        let mut page_table = PageTable::new().expect("OOM");
        let mut frames = Vec::new();

        let skernel = link_symbol!(skernel);
        let ekernel = link_symbol!(ekernel);

        // 恒等映射内核 + 额外空间（供页表分配）
        let map_end = ekernel + 0x10000;
        map_segment(&mut page_table, &mut frames, skernel, map_end,
                    PTEFlags::R | PTEFlags::W | PTEFlags::X);

        // 映射剩余物理内存
        map_segment(&mut page_table, &mut frames, map_end, crate::config::MEMORY_END,
                    PTEFlags::R | PTEFlags::W);

        map_segment(&mut page_table, &mut frames, 0x1000_0000, 0x1000_9000,
                    PTEFlags::R | PTEFlags::W);

        // 映射 TRAMPOLINE 到 __alltraps 所在物理页（供内核访问）
        extern "C" { fn __alltraps(); }
        let trampoline_pa = __alltraps as usize;
        let trampoline_ppn = PhysAddr(trampoline_pa).floor();
        page_table.map(
            VirtAddr(TRAMPOLINE),
            trampoline_ppn,
            PTEFlags::R | PTEFlags::X,
        );

        // 映射 TRAP_CONTEXT_BASE（内核可读写）
        // 注意：此处仅为内核能访问而保留虚拟地址空间，实际每进程映射到自己的物理页
        page_table.map(
            VirtAddr(crate::config::TRAP_CONTEXT_BASE),
            PhysPageNum(0), // 占位，实际由各进程映射
            PTEFlags::R | PTEFlags::W,
        );

        Self {
            page_table,
            areas: Vec::new(),
            frames,
        }
    }

    /// 创建一个空的地址空间（用于用户进程）
    pub fn new_bare() -> Self {
        let pt = PageTable::new().expect("OOM");
        Self {
            page_table: pt,
            areas: Vec::new(),
            frames: Vec::new(),
        }
    }

    pub fn released() -> Self {
        Self {
            page_table: PageTable::empty(),
            areas: Vec::new(),
            frames: Vec::new(),
        }
    }

    /// Create a private copy of a user address space for fork/clone.  This is
    /// deliberately eager-copy rather than copy-on-write: it is simple,
    /// deterministic and sufficient for the single-core contest workload.
    /// The caller maps its own trap-context page afterwards.
    pub fn from_existed_user(parent: &MemorySet, trampoline_pa: usize) -> Self {
        let mut memory_set = Self::new_bare();
        memory_set.map_trampoline(trampoline_pa);
        for area in &parent.areas {
            let start = area.vaddr;
            let end = start + area.pages * crate::config::PAGE_SIZE;
            memory_set.insert_framed_area(VirtAddr(start), VirtAddr(end), area.flags);
            for page in 0..area.pages {
                let va = start + page * crate::config::PAGE_SIZE;
                let source = parent
                    .page_table
                    .find_pte(VirtAddr(va))
                    .expect("parent user mapping disappeared");
                let destination = memory_set
                    .page_table
                    .find_pte(VirtAddr(va))
                    .expect("child user mapping missing");
                unsafe {
                    core::ptr::copy_nonoverlapping(
                        source.ppn().get_addr().0 as *const u8,
                        destination.ppn().get_addr().0 as *mut u8,
                        crate::config::PAGE_SIZE,
                    );
                }
            }
        }
        memory_set
    }

    /// 获取 satp 值
    pub fn token(&self) -> usize {
        self.page_table.token()
    }

    /// 激活地址空间
    pub fn activate(&self) {
        unsafe {
            satp::write(self.token());
            core::arch::asm!("sfence.vma");
        }
    }

    /// 分配物理页并映射一段虚拟地址区间
    pub fn insert_framed_area(
        &mut self,
        start_va: VirtAddr,
        end_va: VirtAddr,
        flags: PTEFlags,
    ) {
        let start_vpn = start_va.floor();
        let end_vpn = end_va.ceil();
        let pages = end_vpn.0 - start_vpn.0;
        for vpn in VPNRange::new(start_vpn, end_vpn) {
            let frame = match frame_alloc() {
                Some(frame) => frame,
                None => {
                    let (used, fresh, recycled, total) =
                        crate::mm::frame_allocator::frame_allocator_stats();
                    let pid = crate::task::current_task()
                        .map(|task| task.pid.0)
                        .unwrap_or(0);
                    panic!(
                        "OOM in insert_framed_area: pid={} start={:#x} end={:#x} pages={} used={} fresh={} recycled={} total={}",
                        pid, start_va.0, end_va.0, pages, used, fresh, recycled, total
                    );
                }
            };
            let ppn = frame.ppn;
            self.frames.push(frame);
            self.page_table.map(vpn.get_addr(), ppn, flags);
        }
        self.areas.push(MapArea {
            vaddr: start_va.0,
            pages,
            flags,
        });
    }

    /// 映射 TRAMPOLINE 页（__alltraps/__restore）
    pub fn map_trampoline(&mut self, trampoline_pa: usize) {
        let trampoline_ppn = PhysAddr(trampoline_pa).floor();
        self.page_table.map(
            VirtAddr(TRAMPOLINE),
            trampoline_ppn,
            PTEFlags::R | PTEFlags::X, // 用户可读可执行
        );
    }

    /// 映射 TrapContext 页
    pub fn map_trap_context(&mut self, trap_cx_va: usize, _tid: usize) {
        let frame = frame_alloc().expect("OOM in map_trap_context");
        let ppn = frame.ppn;
        self.page_table.map(
            VirtAddr(trap_cx_va),
            ppn,
            PTEFlags::R | PTEFlags::W, // 内核读写，用户不可访问
        );
        self.frames.push(frame);
    }

    /// 获取 TrapContext 页的物理地址
    pub fn get_trap_context_phys(&self, trap_cx_va: usize) -> usize {
        let entry = self.page_table.find_pte(VirtAddr(trap_cx_va));
        entry.unwrap().ppn().get_addr().0
    }

    /// 加载 ELF（简化版：调用 elf.rs 中的 load_elf）
    pub fn load_elf(&mut self, elf_data: &[u8]) -> (usize, usize) {
        crate::task::elf::load_elf(self, elf_data)
    }

    pub fn user_heap_base(&self) -> usize {
        let stack_bottom = crate::config::USER_STACK_BASE - crate::config::USER_STACK_SIZE;
        let mut end = 0x10_000usize;
        for area in &self.areas {
            if area.vaddr < stack_bottom {
                end = end.max(area.vaddr + area.pages * crate::config::PAGE_SIZE);
            }
        }
        (end + crate::config::PAGE_SIZE - 1) & !(crate::config::PAGE_SIZE - 1)
    }

    pub fn map_user_range(&mut self, start: usize, end: usize, flags: PTEFlags) {
        if end > start {
            self.insert_framed_area(VirtAddr(start), VirtAddr(end), flags | PTEFlags::U);
        }
    }

    pub fn reserve_user_range(&mut self, start: usize, end: usize, flags: PTEFlags) {
        if end <= start {
            return;
        }
        let start = start & !(crate::config::PAGE_SIZE - 1);
        let end = (end + crate::config::PAGE_SIZE - 1) & !(crate::config::PAGE_SIZE - 1);
