const PER_TASK_TIMEOUT: usize = 10 * CLOCK_FREQ;

lazy_static! {
    static ref TASK_START_TICK: Mutex<Option<(usize, usize)>> = Mutex::new(None);
}

/// Called from the trap handler on every timer tick.
/// Kills the current task if its wall-clock runtime exceeds the per-task budget.
pub fn check_per_task_timeout() {
    let task = match current_task() {
        Some(t) => t,
        None => return,
    };
    let pid = task.pid.0;
    drop(task);
    let mut start = TASK_START_TICK.lock();
    match start.as_ref() {
        Some((stored_pid, tick)) if *stored_pid == pid => {
            if get_time() - *tick > PER_TASK_TIMEOUT {
                crate::println!("[watchdog] task {} exceeded budget, killing", pid);
                *start = None;
                drop(start);
                exit_current_and_run_next(124);
            }
        }
        _ => {
            *start = Some((pid, get_time()));
        }
    }
}

