const SIGCHLD_BIT: u64 = 1u64 << (17 - 1);

/// 让当前任务主动让出 CPU
pub fn suspend_current_and_run_next() {
    let task = take_current_task().unwrap();
    let mut inner = task.acquire_inner_lock();
    let task_cx_ptr = &mut inner.task_cx as *mut TaskContext;
    inner.task_status = TaskStatus::Ready;
    drop(inner);
    add_task(task);
    schedule(task_cx_ptr);
}

/// 阻塞当前任务
pub fn block_current_and_run_next() {
    let task = take_current_task().unwrap();
    let mut inner = task.acquire_inner_lock();
    let task_cx_ptr = &mut inner.task_cx as *mut TaskContext;
    inner.task_status = TaskStatus::Interruptible;
    drop(inner);
    sleep_interruptible(task);
    schedule(task_cx_ptr);
}

pub fn sleep_current_until(deadline: crate::timer::TimeSpec) {
    let task = take_current_task().unwrap();
    let mut inner = task.acquire_inner_lock();
    let task_cx_ptr = &mut inner.task_cx as *mut TaskContext;
    inner.task_status = TaskStatus::Interruptible;
    drop(inner);
    sleep_until(task, deadline);
    schedule(task_cx_ptr);
}

pub fn sleep_current_on_futex(key: usize) {
    let task = take_current_task().unwrap();
    let mut inner = task.acquire_inner_lock();
    let task_cx_ptr = &mut inner.task_cx as *mut TaskContext;
    inner.task_status = TaskStatus::Interruptible;
    drop(inner);
    sleep_futex(task, key);
    schedule(task_cx_ptr);
}

pub fn exit_current_and_run_next(exit_code: u32) -> ! {
    let task = take_current_task().unwrap();
    clear_child_tid_and_wake(&task);
    if let Some(mgr) = crate::fs::manager::FS_MANAGER.lock().as_mut() {
        mgr.exit_process(task.pid.0);
    }
    task.release_user_memory();
    // 简化的退出逻辑
    let mut inner = task.acquire_inner_lock();
    inner.task_status = TaskStatus::Zombie;
    inner.exit_code = exit_code;
    let is_runner_root = inner.parent.is_none();
    let pid = task.pid.0;
    // 通知父进程
    if let Some(parent_weak) = inner.parent.as_ref() {
        if let Some(parent) = parent_weak.upgrade() {
            parent.acquire_inner_lock().pending_signals |= SIGCHLD_BIT;
            wake_interruptible(parent);
        }
    }
    drop(inner);
    remove_queued_task(pid);

    // The test runner owns only its root tasks.  Forked children retain a
    // parent and therefore cannot accidentally advance the next test group.
    if is_runner_root {
        let _ = crate::test_runner::on_root_task_exit(exit_code);
    }
    manager::park_zombie(task);
    let mut _unused = TaskContext::zero_init();
    schedule(&mut _unused as *mut _);
    panic!("Unreachable after exit");
}

pub fn do_exit(task: &TaskControlBlock, exit_code: u32) {
    clear_child_tid_and_wake(task);
    if let Some(mgr) = crate::fs::manager::FS_MANAGER.lock().as_mut() {
        mgr.exit_process(task.pid.0);
    }
    task.release_user_memory();
    let mut inner = task.acquire_inner_lock();
    inner.task_status = TaskStatus::Zombie;
    inner.exit_code = exit_code;
    let parent = inner.parent.as_ref().and_then(|weak| weak.upgrade());
    let pid = task.pid.0;
    drop(inner);
    remove_queued_task(pid);
    if let Some(parent) = parent {
        parent.acquire_inner_lock().pending_signals |= SIGCHLD_BIT;
        wake_interruptible(parent);
    }
}

fn clear_child_tid_and_wake(task: &TaskControlBlock) {
    let clear_child_tid = task.acquire_inner_lock().clear_child_tid;
    if clear_child_tid == 0 {
        return;
    }
    let token = task.get_user_token();
    if let Some(pa) = crate::mm::virt_to_phys(token, clear_child_tid) {
        unsafe {
            *(pa as *mut u32) = 0;
        }
        wake_futex(clear_child_tid, usize::MAX);
    }
}

