//! 任务管理器 — 就绪队列 & 可中断睡眠队列

use super::task::TaskControlBlock;
use crate::timer::TimeSpec;
use alloc::collections::VecDeque;
use alloc::sync::Arc;
use alloc::vec::Vec;
use spin::Mutex;
use lazy_static::*;

pub struct TaskManager {
    pub ready_queue: VecDeque<Arc<TaskControlBlock>>,
    pub sleeping: Vec<(Arc<TaskControlBlock>, TimeSpec)>,
    pub interruptible_queue: VecDeque<Arc<TaskControlBlock>>,
    pub futex_waiters: Vec<(usize, Arc<TaskControlBlock>)>,
    pub zombies: Vec<Arc<TaskControlBlock>>,
}

impl TaskManager {
    pub fn new() -> Self {
        Self {
            ready_queue: VecDeque::new(),
            sleeping: Vec::new(),
            interruptible_queue: VecDeque::new(),
            futex_waiters: Vec::new(),
            zombies: Vec::new(),
        }
    }
}

lazy_static! {
    pub static ref TASK_MANAGER: Mutex<TaskManager> = Mutex::new(TaskManager::new());
}

pub fn add_task(task: Arc<TaskControlBlock>) {
    TASK_MANAGER.lock().ready_queue.push_back(task);
}

pub fn fetch_task() -> Option<Arc<TaskControlBlock>> {
    do_wake_expired();
    let mut mgr = TASK_MANAGER.lock();
    mgr.ready_queue.pop_front()
}

pub fn park_zombie(task: Arc<TaskControlBlock>) {
    TASK_MANAGER.lock().zombies.push(task);
}

pub fn reap_zombies() {
    TASK_MANAGER.lock().zombies.clear();
}

pub fn has_sleeping_tasks() -> bool {
    !TASK_MANAGER.lock().sleeping.is_empty()
}

pub fn sleep_interruptible(task: Arc<TaskControlBlock>) {
    TASK_MANAGER.lock().interruptible_queue.push_back(task);
}

pub fn sleep_until(task: Arc<TaskControlBlock>, deadline: TimeSpec) {
    TASK_MANAGER.lock().sleeping.push((task, deadline));
}

pub fn sleep_futex(task: Arc<TaskControlBlock>, key: usize) {
    TASK_MANAGER.lock().futex_waiters.push((key, task));
}

pub fn remove_queued_task(pid: usize) {
    let mut manager = TASK_MANAGER.lock();
    manager.ready_queue.retain(|task| task.pid.0 != pid);
    manager.interruptible_queue.retain(|task| task.pid.0 != pid);
    manager.sleeping.retain(|(task, _)| task.pid.0 != pid);
    manager.futex_waiters.retain(|(_, task)| task.pid.0 != pid);
}

pub fn wake_futex(key: usize, count: usize) -> usize {
    let mut manager = TASK_MANAGER.lock();
    let mut woke = 0usize;
    let mut index = 0usize;
    while index < manager.futex_waiters.len() && woke < count {
        if manager.futex_waiters[index].0 == key {
            let (_, task) = manager.futex_waiters.remove(index);
            {
                let mut inner = task.acquire_inner_lock();
                inner.task_status = super::TaskStatus::Ready;
            }
            manager.ready_queue.push_back(task);
            woke += 1;
        } else {
            index += 1;
        }
    }
    woke
}

pub fn wake_interruptible(task: Arc<TaskControlBlock>) {
    let pid = task.pid.0;
    let mut manager = TASK_MANAGER.lock();
    manager.interruptible_queue.retain(|queued| queued.pid.0 != pid);
    manager.sleeping.retain(|(queued, _)| queued.pid.0 != pid);
    manager.futex_waiters.retain(|(_, queued)| queued.pid.0 != pid);
    if manager.ready_queue.iter().any(|queued| queued.pid.0 == pid) {
        return;
    }
    {
        let mut inner = task.acquire_inner_lock();
        if inner.task_status != super::TaskStatus::Zombie {
            inner.task_status = super::TaskStatus::Ready;
        }
    }
    manager.ready_queue.push_back(task);
}

fn mark_signal(task: &Arc<TaskControlBlock>, bit: u64, make_ready: bool) {
    let mut inner = task.acquire_inner_lock();
    inner.pending_signals |= bit;
    if make_ready && inner.task_status != super::TaskStatus::Zombie {
        inner.task_status = super::TaskStatus::Ready;
    }
}

pub fn signal_task(pid: usize, signal: usize) -> bool {
    if signal == 0 || signal > 64 {
        return false;
    }
    let bit = 1u64 << (signal - 1);
    let mut manager = TASK_MANAGER.lock();
    if let Some(task) = manager.ready_queue.iter().find(|task| task.pid.0 == pid) {
        mark_signal(task, bit, false);
        return true;
    }
    if let Some(index) = manager.interruptible_queue.iter().position(|task| task.pid.0 == pid) {
        if let Some(task) = manager.interruptible_queue.remove(index) {
            mark_signal(&task, bit, true);
            manager.ready_queue.push_back(task);
            return true;
        }
    }
    if let Some(index) = manager.sleeping.iter().position(|(task, _)| task.pid.0 == pid) {
        let (task, _) = manager.sleeping.remove(index);
        mark_signal(&task, bit, true);
        manager.ready_queue.push_back(task);
        return true;
    }
    if let Some(index) = manager.futex_waiters.iter().position(|(_, task)| task.pid.0 == pid) {
        let (_, task) = manager.futex_waiters.remove(index);
        mark_signal(&task, bit, true);
        manager.ready_queue.push_back(task);
        return true;
    }
    if let Some(task) = manager.zombies.iter().find(|task| task.pid.0 == pid) {
        mark_signal(task, bit, false);
        return true;
    }
    false
}

pub fn do_wake_expired() {
    let now = TimeSpec::now();
    let all_sleeping = {
        let mut mgr = TASK_MANAGER.lock();
        core::mem::take(&mut mgr.sleeping)
    };
    let mut ready_tasks = Vec::new();
    let mut remaining = Vec::new();
    for (task, deadline) in all_sleeping {
        if deadline <= now {
            let mut inner = task.acquire_inner_lock();
            inner.task_status = super::TaskStatus::Ready;
            drop(inner);
            ready_tasks.push(task);
        } else {
            remaining.push((task, deadline));
        }
    }
    let mut mgr = TASK_MANAGER.lock();
    mgr.sleeping = remaining;
    for task in ready_tasks {
        mgr.ready_queue.push_back(task);
    }
}

pub fn terminate_ready_task(pid: usize, exit_code: u32) -> bool {
    let task = {
        let mut manager = TASK_MANAGER.lock();
        if let Some(index) = manager.ready_queue.iter().position(|task| task.pid.0 == pid) {
            manager.ready_queue.remove(index)
        } else if let Some(index) = manager.interruptible_queue.iter().position(|task| task.pid.0 == pid) {
            manager.interruptible_queue.remove(index)
        } else if let Some(index) = manager.futex_waiters.iter().position(|(_, task)| task.pid.0 == pid) {
            Some(manager.futex_waiters.remove(index).1)
        } else if let Some(index) = manager.sleeping.iter().position(|(task, _)| task.pid.0 == pid) {
            Some(manager.sleeping.remove(index).0)
        } else {
            None
        }
    };
    if let Some(task) = task {
        super::do_exit(&task, exit_code);
        true
    } else {
        false
    }
}

