    loop {
        reap_zombies();
        let mut processor = PROCESSOR.lock();
        if let Some(task) = fetch_task() {
            if let Some(mgr) = crate::fs::manager::FS_MANAGER.lock().as_mut() {
                mgr.switch_to_process(task.pid.0);
            }
            let idle_task_cx_ptr = processor.get_idle_task_cx_ptr();
            let next_task_cx_ptr = {
                let mut inner = task.acquire_inner_lock();
                inner.task_status = TaskStatus::Running;
                &inner.task_cx as *const TaskContext
            };
            processor.current = Some(task);
            drop(processor);
            unsafe {
                __switch(idle_task_cx_ptr, next_task_cx_ptr);
            }
        } else {
            drop(processor);
            // 无任务可运行，wfi
            if has_sleeping_tasks() {
                continue;
            }
            crate::sbi::shutdown(false);
        }
    }
}

pub fn take_current_task() -> Option<Arc<TaskControlBlock>> {
    PROCESSOR.lock().take_current()
}

pub fn current_task() -> Option<Arc<TaskControlBlock>> {
    PROCESSOR.lock().current()
}

pub fn current_user_token() -> usize {
    current_task().unwrap().get_user_token()
}

pub fn current_trap_cx() -> &'static mut TrapContext {
    let task = current_task().unwrap();
    let trap_cx_ppn = task.acquire_inner_lock().trap_cx_ppn;
    if trap_cx_ppn != 0 {
        let pa = trap_cx_ppn << crate::config::PAGE_SIZE_BITS;
        return unsafe { &mut *(pa as *mut TrapContext) };
    }
    let trap_cx_va = task.trap_cx_user_va();
    // 通过用户页表翻译 TrapContext 虚拟地址（该页仅在用户页表中映射到实际物理页）
    let token = task.get_user_token();
    let pa = crate::mm::virt_to_phys(token, trap_cx_va).unwrap();
    unsafe { &mut *(pa as *mut TrapContext) }
}

pub fn schedule(switched_task_cx_ptr: *mut TaskContext) {
    let idle_task_cx_ptr = PROCESSOR.lock().get_idle_task_cx_ptr();
    unsafe {
        __switch(switched_task_cx_ptr, idle_task_cx_ptr);
    }
}

