//! ELF 可执行文件加载器

use crate::mm::{MapPermission, MemorySet, VirtAddr};
use alloc::vec::Vec;
use core::mem::size_of;
use xmas_elf::ElfFile;

fn aligned_elf_image(elf_data: &[u8]) -> Vec<usize> {
    let word_size = size_of::<usize>();
    let word_count = (elf_data.len() + word_size - 1) / word_size;
    let mut image = Vec::new();
    image.resize(word_count, 0);
    if !elf_data.is_empty() {
        unsafe {
            core::ptr::copy_nonoverlapping(
                elf_data.as_ptr(),
                image.as_mut_ptr() as *mut u8,
                elf_data.len(),
            );
        }
    }
    image
}

/// 将 ELF 数据加载到给定的 MemorySet 中
/// 返回 (入口地址, 用户栈顶部地址)
pub fn load_elf(memory_set: &mut MemorySet, elf_data: &[u8]) -> (usize, usize) {
    let aligned_image = aligned_elf_image(elf_data);
    let aligned_bytes = unsafe {
        core::slice::from_raw_parts(aligned_image.as_ptr() as *const u8, elf_data.len())
    };
    let elf = ElfFile::new(aligned_bytes).expect("Invalid ELF");

    // 检查架构
    assert_eq!(
        elf.header.pt2.machine().as_machine(),
        xmas_elf::header::Machine::RISC_V,
        "Not a RISC-V ELF"
    );

    let entry = elf.header.pt2.entry_point() as usize;

    // 加载所有可加载段
    for (i, ph) in elf.program_iter().enumerate() {
        let ph_type = ph.get_type();
        if ph_type.unwrap_or(xmas_elf::program::Type::Null) != xmas_elf::program::Type::Load {
            continue;
        }
        let vaddr = ph.virtual_addr() as usize;
        let mem_size = ph.mem_size() as usize;
        let offset = ph.offset() as usize;
        let file_size = ph.file_size() as usize;
        let flags = ph.flags();

        let mut perm = MapPermission::U;
        if flags.is_read() { perm |= MapPermission::R; }
        if flags.is_write() { perm |= MapPermission::W; }
        if flags.is_execute() { perm |= MapPermission::X; }

        // 分配物理页并映射
        let start_va = VirtAddr(vaddr);
        let end_va = VirtAddr(vaddr + mem_size);
        memory_set.insert_framed_area(start_va, end_va, perm);

        // 从 ELF 数据拷贝内容
        if file_size > 0 {
            unsafe {
                let src = &aligned_bytes[offset..offset + file_size];
                let mut remaining = file_size;
                let mut cur: usize = vaddr;
                while remaining > 0 {
                    let page_off = cur & 0xfff;
                    let copy_len = (0x1000 - page_off).min(remaining);
                    let dst = cur;
                    let token = memory_set.token();
                    if let Some(pa) = crate::mm::virt_to_phys(token, dst) {
                        core::ptr::copy_nonoverlapping(
                            src.as_ptr().add(cur - vaddr),
                            pa as *mut u8,
                            copy_len,
                        );
                    }
                    cur += copy_len;
                    remaining -= copy_len;
                }
            }
        }
    }

    // 分配并映射用户栈
    let stack_top = crate::config::USER_STACK_BASE;
    let stack_bottom = stack_top - crate::config::USER_STACK_SIZE;
    memory_set.insert_framed_area(
        VirtAddr(stack_bottom),
        VirtAddr(stack_top),
        MapPermission::R | MapPermission::W | MapPermission::U,
    );

    (entry, stack_top)
}

//! PID 分配器 & 内核栈管理

use crate::config::{KERNEL_HEAP_SIZE, PAGE_SIZE};
use alloc::vec::Vec;
use spin::Mutex;
use lazy_static::*;

/// PID 分配器
pub struct PidAllocator {
    current: usize,
    recycled: Vec<usize>,
}

impl PidAllocator {
    pub fn new() -> Self {
        // Linux userspace reserves pid 0 for the scheduler/idle context.
        Self { current: 1, recycled: Vec::new() }
    }
    pub fn alloc(&mut self) -> usize {
        if let Some(pid) = self.recycled.pop() {
            pid
        } else {
            let pid = self.current;
            self.current += 1;
            pid
        }
    }
    pub fn dealloc(&mut self, pid: usize) {
        self.recycled.push(pid);
    }
}

lazy_static! {
    static ref PID_ALLOCATOR: Mutex<PidAllocator> = Mutex::new(PidAllocator::new());
}

pub struct PidHandle(pub usize);

impl PidHandle {
    pub fn alloc() -> Self {
        Self(PID_ALLOCATOR.lock().alloc())
    }
}

impl Drop for PidHandle {
    fn drop(&mut self) {
        PID_ALLOCATOR.lock().dealloc(self.0);
    }
}

/// 内核栈
pub struct KernelStack {
    pid: usize,
    stack: Vec<u8>,
}

impl KernelStack {
    pub fn alloc(pid: usize) -> Self {
        // Static glibc test programs exercise deeper syscall paths
        // (EXT4, wait/exec, formatting).  Two pages is too tight and can
        // corrupt saved Rust stack frames across a context switch.
        let stack = vec![0u8; PAGE_SIZE * 16];
        Self { pid, stack }
    }
    pub fn get_top(&self) -> usize {
        self.stack.as_ptr() as usize + self.stack.len()
    }
}

impl Drop for KernelStack {
    fn drop(&mut self) {
        // Vec 自动释放
    }
}

/// 根据 tid 生成 TrapContext 在 TRAP_CONTEXT_BASE 的虚拟地址偏移
/// 每个任务占用一页（0x1000），不同任务使用不同的偏移
pub fn trap_cx_bottom_from_tid(tid: usize) -> usize {
    crate::config::TRAP_CONTEXT_BASE - tid * PAGE_SIZE
}

pub fn ustack_bottom_from_tid(tid: usize) -> usize {
    crate::config::USER_STACK_BASE - tid * PAGE_SIZE
}

use crate::config::TRAMPOLINE;
use crate::println;
use crate::syscall::syscall;
use crate::task::{
    current_task, current_trap_cx, do_wake_expired, suspend_current_and_run_next,
};
use crate::timer::set_next_trigger;
pub use context::{GeneralRegs, TrapContext};
mod context;
use core::arch::global_asm;
use riscv::register::{
    scause::{self, Exception, Interrupt, Trap},
    sepc, sie, stval, stvec,
};
use riscv::register::stvec::TrapMode;

global_asm!(include_str!("trap.S"));

extern "C" {
    pub fn __alltraps();
    pub fn __restore();
}

pub fn init() {
    // 内核模式 stvec 直接指向 trap_from_kernel
    set_kernel_trap_entry();
    crate::timer::set_next_trigger();
    unsafe {
        sie::set_stimer();
    }
}

fn set_kernel_trap_entry() {
    unsafe {
        stvec::write(trap_from_kernel as usize, TrapMode::Direct);
    }
}

fn set_user_trap_entry() {
    // 用户态 stvec 指向 __alltraps 在 TRAMPOLINE 中的实际偏移
    unsafe {
        stvec::write(TRAMPOLINE + (__alltraps as usize & 0xfff), TrapMode::Direct);
    }
}

pub fn enable_timer_interrupt() {
    unsafe {
        sie::set_stimer();
        riscv::register::sstatus::set_sie();
    }
}

#[unsafe(no_mangle)]
pub fn trap_handler() -> ! {
    // 进入内核后，stvec 改为内核入口
    set_kernel_trap_entry();

    let scause = scause::read();
    let stval_val = stval::read();
    match scause.cause() {
        Trap::Exception(Exception::UserEnvCall) => {
            // ecall 系统调用
            let mut cx = current_trap_cx();
            cx.gp.pc += 4; // 跳过 ecall 指令，回到下一条
            let syscall_id = cx.gp.a7;
            let result = syscall(
                syscall_id, // syscall ID
                [cx.gp.a0, cx.gp.a1, cx.gp.a2, cx.gp.a3, cx.gp.a4, cx.gp.a5],
            );
            // sys_exec 可能改变了地址空间，重新获取 TrapContext
            if syscall_id != crate::syscall::SYS_EXECVE || result < 0 {
                cx = current_trap_cx();
                cx.gp.a0 = result as usize;
            }
        }
        Trap::Exception(Exception::StoreFault)
        | Trap::Exception(Exception::StorePageFault)
        | Trap::Exception(Exception::InstructionFault)
        | Trap::Exception(Exception::InstructionPageFault)
        | Trap::Exception(Exception::LoadFault)
        | Trap::Exception(Exception::LoadPageFault) => {
            if matches!(
                scause.cause(),
                Trap::Exception(Exception::StorePageFault)
                    | Trap::Exception(Exception::LoadPageFault)
                    | Trap::Exception(Exception::InstructionPageFault)
            ) && stval_val >= crate::config::PAGE_SIZE
            {
                if let Some(task) = current_task() {
                    let handled = task.vm.lock().handle_lazy_page_fault(stval_val);
                    drop(task);
                    if handled {
                        trap_return();
                    }
                }
            }
            if let Some(task) = current_task() {
                drop(task);
                let cx = current_trap_cx();
                let exit_code = if matches!(scause.cause(), Trap::Exception(Exception::InstructionPageFault))
                    && stval_val < crate::config::PAGE_SIZE
                {
                    (cx.gp.a0 & 0xff) as u32
                } else {
                    139
                };
                crate::task::exit_current_and_run_next(exit_code);
            }
            // 缺页异常 — 简化处理：直接 panic
            panic!(
                "Page fault at {:#x}, cause: {:?}, stval: {:#x}",
                sepc::read(),
                scause.cause(),
                stval_val,
            );
        }
        Trap::Exception(Exception::IllegalInstruction) => {
            if let Some(task) = current_task() {
                drop(task);
                crate::task::exit_current_and_run_next(132);
            }
            panic!(
                "Illegal instruction at {:#x}, stval: {:#x}",
                sepc::read(),
                stval_val,
            );
        }
        Trap::Exception(Exception::Breakpoint) => {
            if let Some(task) = current_task() {
                drop(task);
                crate::task::exit_current_and_run_next(133);
            }
            panic!(
                "Breakpoint at {:#x}, stval: {:#x}",
                sepc::read(),
                stval_val,
            );
        }
        Trap::Interrupt(Interrupt::SupervisorTimer) => {
            do_wake_expired();
            set_next_trigger();
            crate::task::check_per_task_timeout();
            suspend_current_and_run_next();
        }
        _ => {
            panic!(
                "Unsupported trap {:?}, sepc = {:#x}, stval = {:#x}!",
                scause.cause(),
                sepc::read(),
                stval_val,
            );
        }
    }
    trap_return();
}

#[unsafe(no_mangle)]
pub fn trap_return() -> ! {
    set_user_trap_entry();
    let task = current_task().unwrap();
    let trap_cx_va = task.trap_cx_user_va();
    let user_satp = task.get_user_token();
    drop(task);
    let restore_va = TRAMPOLINE + (__restore as usize & 0xfff);
    unsafe {
        core::arch::asm!(
            "fence.i",
            "jalr zero, {restore_va}, 0",
            restore_va = in(reg) restore_va,
            in("a0") trap_cx_va,
            in("a1") user_satp,
            options(noreturn)
        );
    }
}

/// 内核中的 trap（通常是 bug）
#[unsafe(no_mangle)]
pub fn trap_from_kernel() -> ! {
    panic!(
        "Trap from kernel! cause: {:?}, sepc: {:#x}, stval: {:#x}",
        scause::read().cause(),
        sepc::read(),
        stval::read(),
    );
}

