/// 通用寄存器（RISC-V 64）
#[repr(C)]
#[derive(Debug, Default, Clone, Copy)]
pub struct GeneralRegs {
    pub pc: usize,   // sepc
    pub ra: usize,
    pub sp: usize,
    pub gp: usize,
    pub tp: usize,
    pub t0: usize,
    pub t1: usize,
    pub t2: usize,
    pub s0: usize,
    pub s1: usize,
    pub a0: usize,
    pub a1: usize,
    pub a2: usize,
    pub a3: usize,
    pub a4: usize,
    pub a5: usize,
    pub a6: usize,
    pub a7: usize,
    pub s2: usize,
    pub s3: usize,
    pub s4: usize,
    pub s5: usize,
    pub s6: usize,
    pub s7: usize,
    pub s8: usize,
    pub s9: usize,
    pub s10: usize,
    pub s11: usize,
    pub t3: usize,
    pub t4: usize,
    pub t5: usize,
    pub t6: usize,
}

/// Trap 上下文（保存在 TRAP_CONTEXT_BASE）
///
/// ⚠️ 布局必须与 trap.S 中的汇编代码严格一致！
///
/// 汇编偏移对照：
///   GeneralRegs:  0*8 .. 31*8  (32 个寄存器)
///   reserved:     32*8         (未使用，对齐填充)
///   origin_a0:    33*8
///   sstatus:      34*8
///   kernel_satp:  35*8
///   trap_handler: 36*8
///   kernel_sp:    37*8
#[repr(C)]
#[derive(Debug, Clone, Copy)]
pub struct TrapContext {
    pub gp: GeneralRegs,          // 0*8 .. 31*8 = 32 个通用寄存器 (256 bytes)
    /// 保留字段（汇编未使用，仅用于对齐）
    pub reserved: usize,          // 32*8
    /// 发生 ecall 前的原始 a0（syscall 重启时需要）
    pub origin_a0: usize,         // 33*8
    /// 陷入时的 sstatus（SPP/SPIE 等）
    pub sstatus: usize,           // 34*8
    /// 内核页表 token (satp)
    pub kernel_satp: usize,       // 35*8
    /// trap_handler 函数地址
    pub trap_handler: usize,      // 36*8
    /// 内核栈指针
    pub kernel_sp: usize,         // 37*8
}

impl TrapContext {
    /// 为用户程序初始化 TrapContext
    pub fn app_init_context(
        entry: usize,
        user_sp: usize,
        kernel_satp: usize,
        trap_handler: usize,
        kernel_sp: usize,
    ) -> Self {
        let mut gp = GeneralRegs::default();
        gp.pc = entry;         // 入口地址 → sepc（sret 后从这里开始执行）
        gp.sp = user_sp;       // 用户栈指针
        Self {
            gp,
            reserved: 0,
            origin_a0: 0,
            // SPIE=1, SPP=0 → sret 后进入 U-mode 且开中断
            sstatus: 0x20 | (3 << 13),
            kernel_satp,
            trap_handler,
            kernel_sp,
        }
    }
}

