/// Write through the process file-descriptor table.  Console output is also
/// represented by fd 1/2 there, so this keeps regular files, pipes and stdout
/// on one ABI path.
pub fn sys_write(fd: usize, buf: usize, count: usize) -> isize {
    let token = crate::task::current_user_token();
    let buffers = match translated_byte_buffer(token, buf as *const u8, count) {
        Ok(b) => b,
        Err(e) => return e,
    };
    let mut data = alloc::vec![0u8; count];
    UserBuffer::new(buffers).read(&mut data);

    let mut guard = FS_MANAGER.lock();
    let mgr = match guard.as_mut() {
        Some(m) => m,
        None => return ENODEV,
    };
    mgr.write(fd, &data)
}

pub fn sys_writev(fd: usize, iov: usize, iovcnt: usize) -> isize {
    let token = crate::task::current_user_token();
    let iovs = match read_iovecs(token, iov, iovcnt) {
        Ok(iovs) => iovs,
        Err(err) => return err,
    };
    let mut total = 0isize;
    for entry in iovs {
        if entry.len == 0 {
            continue;
        }
        let written = sys_write(fd, entry.base, entry.len);
        if written < 0 {
            return if total > 0 { total } else { written };
        }
        total += written;
        if written as usize != entry.len {
            break;
        }
    }
    total
}

pub fn sys_readv(fd: usize, iov: usize, iovcnt: usize) -> isize {
    let token = crate::task::current_user_token();
    let iovs = match read_iovecs(token, iov, iovcnt) {
        Ok(iovs) => iovs,
        Err(err) => return err,
    };
    let mut total = 0isize;
    for entry in iovs {
        if entry.len == 0 {
            continue;
        }
        let read = sys_read(fd, entry.base, entry.len);
        if read < 0 {
            return if total > 0 { total } else { read };
        }
        total += read;
        if read as usize != entry.len {
            break;
        }
    }
    total
}

fn read_iovecs(token: usize, iov: usize, iovcnt: usize) -> Result<Vec<IoVec>, isize> {
    const MAX_IOV: usize = 1024;
    if iovcnt > MAX_IOV {
        return Err(EINVAL);
    }
    let mut result = Vec::new();
    for index in 0..iovcnt {
        let va = iov + index * core::mem::size_of::<IoVec>();
        let pa = virt_to_phys(token, va).ok_or(EFAULT)?;
        let entry = unsafe { *(pa as *const IoVec) };
        result.push(entry);
    }
    Ok(result)
}

pub fn sys_openat(dirfd: usize, path: *const u8, flags: usize, _mode: usize) -> isize {
    let token = crate::task::current_user_token();
    let path_str = match translated_str(token, path) {
        Ok(s) => s,
        Err(e) => return e,
    };
    let mut mgr = FS_MANAGER.lock();
    let mgr = match mgr.as_mut() {
        Some(m) => m,
        None => return ENODEV,
    };

    let path = match mgr.resolve_at_path(dirfd, path_str.as_bytes()) {
        Ok(path) => path,
        Err(err) => return err,
    };
    match mgr.open(&path, flags) {
        Ok(fd) => fd as isize,
        Err(e) => e,
    }
}

pub fn sys_read(fd: usize, buf: usize, count: usize) -> isize {
    let token = crate::task::current_user_token();
    let buffer = match translated_byte_buffer(token, buf as *const u8, count) {
        Ok(b) => b,
        Err(e) => return e,
    };
    let total_len: usize = buffer.iter().map(|b| b.len()).sum();
    let mut read_buf = alloc::vec![0u8; total_len];
    let mut user_buffer = Some(buffer);

    for _ in 0..128 {
        let (n, pipe_wait) = {
            let mut guard = FS_MANAGER.lock();
            let mgr = match guard.as_mut() {
                Some(m) => m,
                None => return ENODEV,
            };
            let n = mgr.read(fd, &mut read_buf);
            (n, n == EAGAIN && mgr.is_pipe_read(fd))
        };
        if pipe_wait {
            crate::task::suspend_current_and_run_next();
            continue;
        }
        if n > 0 {
            let mut ub = UserBuffer::new(user_buffer.take().unwrap());
            ub.write(&read_buf[..n as usize]);
        }
        return n;
    }
    0
}

pub fn sys_pread64(fd: usize, buf: usize, count: usize, offset: isize) -> isize {
    if offset < 0 {
        return EINVAL;
    }
    let token = crate::task::current_user_token();
    let buffers = match translated_byte_buffer(token, buf as *const u8, count) {
        Ok(buffers) => buffers,
        Err(err) => return err,
    };
    let mut tmp = alloc::vec![0u8; count];
    let read = {
        let guard = FS_MANAGER.lock();
        let mgr = match guard.as_ref() { Some(mgr) => mgr, None => return ENODEV };
        mgr.read_at(fd, offset as usize, &mut tmp)
    };
    if read > 0 {
        UserBuffer::new(buffers).write(&tmp[..read as usize]);
    }
    read
}

