const FD_CAPACITY: usize = 256;

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct FileDescriptor {
    pub object_id: usize,
    pub cloexec: bool,
    pub nonblock: bool,
}

impl FileDescriptor {
    pub const fn new(object_id: usize) -> Self {
        Self {
            object_id,
            cloexec: false,
            nonblock: false,
        }
    }
}

#[derive(Clone)]
pub struct FdTable {
    slots: [Option<FileDescriptor>; FD_CAPACITY],
    hard_limit: usize,
}

impl FdTable {
    pub const fn new(hard_limit: usize) -> Self {
        Self {
            slots: [None; FD_CAPACITY],
            hard_limit: if hard_limit < FD_CAPACITY {
                hard_limit
            } else {
                FD_CAPACITY
            },
        }
    }

    #[allow(dead_code)]
    pub const fn hard_limit(&self) -> usize {
        self.hard_limit
    }

    pub fn set_hard_limit(&mut self, limit: usize) {
        self.hard_limit = if limit < FD_CAPACITY {
            limit
        } else {
            FD_CAPACITY
        };
    }

    pub fn insert(&mut self, descriptor: FileDescriptor) -> Result<usize, ()> {
        self.insert_from(0, descriptor)
    }

    pub fn insert_from(&mut self, min_fd: usize, descriptor: FileDescriptor) -> Result<usize, ()> {
        if min_fd >= self.hard_limit {
            return Err(());
        }
        let relative = self.slots[min_fd..self.hard_limit]
            .iter()
            .position(Option::is_none)
            .ok_or(())?;
        let fd = min_fd + relative;
        self.slots[fd] = Some(descriptor);
        Ok(fd)
    }

    pub fn reserve(&mut self, fd: usize, descriptor: FileDescriptor) -> Result<(), ()> {
        if fd >= self.hard_limit {
            return Err(());
        }
        self.slots[fd] = Some(descriptor);
        Ok(())
    }

    pub fn get(&self, fd: usize) -> Option<FileDescriptor> {
        self.slots.get(fd).copied().flatten()
    }

    pub fn get_mut(&mut self, fd: usize) -> Option<&mut FileDescriptor> {
        self.slots.get_mut(fd).and_then(Option::as_mut)
    }

    pub fn close(&mut self, fd: usize) -> Result<FileDescriptor, ()> {
        self.slots.get_mut(fd).and_then(Option::take).ok_or(())
    }

    pub fn dup(&mut self, old_fd: usize) -> Result<usize, ()> {
        let descriptor = self.get(old_fd).ok_or(())?;
        self.insert(descriptor)
    }

    pub fn dup3(&mut self, old_fd: usize, new_fd: usize, cloexec: bool) -> Result<usize, ()> {
        if old_fd == new_fd || new_fd >= self.hard_limit {
            return Err(());
        }
        let mut descriptor = self.get(old_fd).ok_or(())?;
        descriptor.cloexec = cloexec;
        self.slots[new_fd] = Some(descriptor);
        Ok(new_fd)
    }
}

pub fn self_test() -> bool {
    let mut table = FdTable::new(16);
    let stdin = match table.insert(FileDescriptor::new(100)) {
        Ok(fd) => fd,
        Err(()) => return false,
    };
    let stdout = match table.insert(FileDescriptor::new(101)) {
        Ok(fd) => fd,
        Err(()) => return false,
    };
    let duplicate = match table.dup(stdout) {
        Ok(fd) => fd,
        Err(()) => return false,
    };

    stdin == 0
        && stdout == 1
        && duplicate == 2
        && table.get(duplicate) == table.get(stdout)
        && table.dup3(stdout, 10, true) == Ok(10)
        && table.get(10).map(|fd| fd.cloexec) == Some(true)
        && table.close(10).is_ok()
        && table.get(10).is_none()
}

//! EXT4 file system layer ? inode lookup, file read

use core::cell::Cell;

const EXT4_MAGIC: u16 = 0xef53;

#[derive(Copy, Clone)]
pub struct Ext4Info {
    pub block_size: usize,
    pub inode_size: usize,
    pub inodes_per_group: usize,
    pub group_desc_size: usize,
}

pub struct Ext4Fs {
    pub info: Ext4Info,
}

#[derive(Clone, Copy)]
pub struct Ext4Inode {
    pub inode_no: u32,
    pub size: usize,
    pub is_dir: bool,
    pub is_file: bool,
}

impl Ext4Fs {
    pub fn new() -> Result<Self, ()> {
        let mut sector = [0u8; 512];
        if crate::drivers::block::read_sector(2, &mut sector).is_err() { return Err(()); }
        let magic = u16::from_le_bytes([sector[0x38], sector[0x39]]);
        if magic != EXT4_MAGIC { return Err(()); }
        let log_block_size = u32::from_le_bytes([sector[24], sector[25], sector[26], sector[27]]);
        let block_size = 1024usize << log_block_size;
        let inode_size = match u16::from_le_bytes([sector[0x58], sector[0x59]]) { 0 => 128, v => v as usize };
        let ipg = u32::from_le_bytes([sector[0x28], sector[0x29], sector[0x2a], sector[0x2b]]) as usize;
        let gd_size = match u16::from_le_bytes([sector[0xfe], sector[0xff]]) { 0..=31 => 32, v => v as usize };
        Ok(Self { info: Ext4Info { block_size, inode_size, inodes_per_group: ipg, group_desc_size: gd_size } })
    }

    pub fn copy_info(&self) -> Self { Self { info: self.info } }

    pub fn read_block(&self, block_id: usize, buf: &mut [u8; 4096]) -> Result<(), ()> {
        if self.info.block_size != 4096 { return Err(()); }
        crate::drivers::block::read_ext4_block(block_id, buf)
    }

    pub fn read_inode(&self, inode_no: u32, out: &mut [u8; 256]) -> Result<(), ()> {
        if inode_no == 0 || self.info.inode_size > out.len() || self.info.inodes_per_group == 0 { return Err(()); }
        let index = inode_no as usize - 1;
        let group = index / self.info.inodes_per_group;
        let idx_in_group = index % self.info.inodes_per_group;
        let dpb = self.info.block_size / self.info.group_desc_size;
        if dpb == 0 { return Err(()); }
        let desc_block = 1 + group / dpb;
        let desc_off = (group % dpb) * self.info.group_desc_size;
        let mut block = [0u8; 4096];
        self.read_block(desc_block, &mut block)?;
        let inode_table_lo = u32::from_le_bytes([block[desc_off+8], block[desc_off+9], block[desc_off+10], block[desc_off+11]]) as usize;
        let inode_table_hi = if self.info.group_desc_size >= 64 {
            u32::from_le_bytes([block[desc_off+0x28], block[desc_off+0x29], block[desc_off+0x2a], block[desc_off+0x2b]]) as usize
        } else { 0 };
        let table_block = (inode_table_hi << 32) | inode_table_lo;
        if table_block == 0 { return Err(()); }
        let inode_block_id = table_block + (idx_in_group * self.info.inode_size) / self.info.block_size;
        let inode_off = (idx_in_group * self.info.inode_size) % self.info.block_size;
        self.read_block(inode_block_id, &mut block)?;
        out[..self.info.inode_size].copy_from_slice(&block[inode_off..inode_off + self.info.inode_size]);
        Ok(())
    }

    pub fn stat_inode(&self, inode_no: u32) -> Result<Ext4Inode, ()> {
        let mut buf = [0u8; 256];
        self.read_inode(inode_no, &mut buf)?;
        let mode = u16::from_le_bytes([buf[0], buf[1]]);
        let size = u32::from_le_bytes([buf[4], buf[5], buf[6], buf[7]]) as usize;
        Ok(Ext4Inode { inode_no, size, is_dir: mode & 0x4000 != 0, is_file: mode & 0x8000 != 0 })
    }

    pub fn lookup(&self, parent_inode: u32, name: &[u8]) -> Result<Ext4Inode, ()> {
        let stat = self.stat_inode(parent_inode)?;
        if !stat.is_dir { return Err(()); }
        let mut inode_buf = [0u8; 256];
        self.read_inode(parent_inode, &mut inode_buf)?;
        let flags = u32::from_le_bytes([inode_buf[0x20], inode_buf[0x21], inode_buf[0x22], inode_buf[0x23]]);
        let mut i_block = [0u8; 60];
        i_block.copy_from_slice(&inode_buf[0x28..0x28 + 60]);
