    pub fs: Ext4Fs,
    pub inode: Ext4Inode,
    pub offset: Cell<usize>,
}

impl Ext4File {
    pub fn read(&mut self, buf: &mut [u8]) -> isize {
        let off = self.offset.get();
        match self.fs.read_file(&self.inode, off, buf) {
            Ok(n) => {
                self.offset.set(off + n);
                n as isize
            }
            Err(()) => crate::syscall::errno::EIO,
        }
    }

    fn clone_file(&self) -> Self {
        Self {
            fs: self.fs.copy_info(),
            inode: self.inode,
            offset: Cell::new(self.offset.get()),
        }
    }
}

