enum FileHandle {
    Stdin,
    Stdout,
    Stderr,
    DevNull,
    DevZero,
    DevRandom,
    Ext4(Ext4File),
    Mem(MemOpenFile),
    Dir { path: Vec<u8>, offset: Cell<usize> },
    PipeRead(usize),
    PipeWrite(usize),
    Socket(usize),
    Epoll(usize),
    EventFd(usize),
    TimerFd(usize),
    SignalFd(usize),
}

impl FileHandle {
    fn descriptor_object(&self) -> usize {
        match self {
            Self::Stdin => STDIN_OBJECT,
            Self::Stdout => STDOUT_OBJECT,
            Self::Stderr => STDERR_OBJECT,
            Self::DevNull => DEV_NULL_OBJECT,
            Self::DevZero => DEV_ZERO_OBJECT,
            Self::DevRandom => DEV_RANDOM_OBJECT,
            Self::Ext4(file) => file.inode.inode_no as usize,
            Self::Mem(file) => 0x2000_0000usize | file.node,
            Self::Dir { .. } => 0x3000_0000,
            Self::PipeRead(pipe) => 0x4000_0000usize | pipe,
            Self::PipeWrite(pipe) => 0x5000_0000usize | pipe,
            Self::Socket(socket) => 0x6000_0000usize | socket,
            Self::Epoll(epoll) => EPOLL_OBJECT_BASE | epoll,
            Self::EventFd(eventfd) => EVENTFD_OBJECT_BASE | eventfd,
            Self::TimerFd(timerfd) => TIMERFD_OBJECT_BASE | timerfd,
            Self::SignalFd(signalfd) => SIGNALFD_OBJECT_BASE | signalfd,
        }
    }

    fn duplicate(&self) -> Self {
        match self {
            Self::Stdin => Self::Stdin,
            Self::Stdout => Self::Stdout,
            Self::Stderr => Self::Stderr,
            Self::DevNull => Self::DevNull,
            Self::DevZero => Self::DevZero,
            Self::DevRandom => Self::DevRandom,
            Self::Ext4(file) => Self::Ext4(file.clone_file()),
            Self::Mem(file) => Self::Mem(MemOpenFile {
                node: file.node,
                offset: Cell::new(file.offset.get()),
            }),
            Self::Dir { path, offset } => Self::Dir { path: path.clone(), offset: Cell::new(offset.get()) },
            Self::PipeRead(pipe) => Self::PipeRead(*pipe),
            Self::PipeWrite(pipe) => Self::PipeWrite(*pipe),
            Self::Socket(socket) => Self::Socket(*socket),
            Self::Epoll(epoll) => Self::Epoll(*epoll),
            Self::EventFd(eventfd) => Self::EventFd(*eventfd),
            Self::TimerFd(timerfd) => Self::TimerFd(*timerfd),
            Self::SignalFd(signalfd) => Self::SignalFd(*signalfd),
        }
    }
}

fn std_fd_table() -> FdTable {
    let mut fd_table = FdTable::new(256);
    let _ = fd_table.reserve(0, FileDescriptor::new(STDIN_OBJECT));
    let _ = fd_table.reserve(1, FileDescriptor::new(STDOUT_OBJECT));
    let _ = fd_table.reserve(2, FileDescriptor::new(STDERR_OBJECT));
    fd_table
}

fn std_files() -> Vec<Option<FileHandle>> {
    vec![
        Some(FileHandle::Stdin),
        Some(FileHandle::Stdout),
        Some(FileHandle::Stderr),
    ]
}

fn duplicate_file_table(files: &[Option<FileHandle>]) -> Vec<Option<FileHandle>> {
    files
        .iter()
        .map(|handle| handle.as_ref().map(FileHandle::duplicate))
        .collect()
}

