fn clear_bss() {
    unsafe extern "C" {
        fn sbss();
        fn ebss();
    }
    unsafe {
        core::slice::from_raw_parts_mut(
            sbss as usize as *mut u8,
            ebss as usize - sbss as usize,
        )
        .fill(0);
    }
}

#[unsafe(no_mangle)]
pub fn loongarch_main() -> ! {
    clear_bss();
    loongarch_csr::init_direct_map();
    loongarch_csr::init_page_walk();
    loongarch_csr::enable_paging();
    console::log_init();
    println!("[kernel-la] HPU OS starting...");

    mm::init();

    unsafe extern "C" {
        fn __alltraps();
        fn __tlb_refill();
    }
    unsafe {
        config::TRAMPOLINE_PA = __alltraps as usize;
        loongarch_csr::set_tlb_refill_entry(__tlb_refill as usize);
    }

    trap::init();
    timer::set_next_trigger();
    drivers::init();
    fs::init();

    if !test_runner::start_from_disk() {
        println!("[kernel-la] no supported test image; no test points selected");
        println!("[kernel-la] all selected test groups finished");
        sbi::shutdown(false);
    }

    task::run_tasks();
}

