// ========== 最简单的系统调用 ==========

pub fn sys_write(fd: usize, buf: usize, count: usize) -> isize {
    // 标准输出或标准错误输出
    if fd == 1 || fd == 2 {
        let token = current_user_token();
        let buffer = match translated_byte_buffer(token, buf as *const u8, count) {
            Ok(b) => b,
            Err(e) => return e,
        };
        let mut total = 0usize;
        for seg in UserBuffer::new(buffer).iter() {
            for &byte in seg.iter() {
                console_putchar(byte as usize);
                total += 1;
            }
        }
        total as isize
    } else {
        // 其他 fd — 暂不支持
        EBADF
    }
}

pub fn sys_exit(exit_code: u32) -> ! {
    info!("[sys_exit] code: {}", exit_code);
    exit_current_and_run_next(exit_code);
}

pub fn sys_exit_group(exit_code: u32) -> ! {
    let task = current_task().unwrap();
    let self_pid = task.pid.0;
    let children: Vec<usize> = {
        let inner = task.acquire_inner_lock();
        inner.children.iter().map(|child| child.pid.0).collect()
    };
    drop(task);
    for pid in children {
        if pid != self_pid {
            let _ = crate::task::terminate_ready_task(pid, exit_code);
        }
    }
    exit_current_and_run_next(exit_code);
}

pub fn sys_getpid() -> isize {
    current_task().unwrap().pid.0 as isize
}

pub fn sys_getppid() -> isize {
    let task = current_task().unwrap();
    let inner = task.acquire_inner_lock();
    match inner.parent.as_ref() {
        Some(parent_weak) => {
            if let Some(parent) = parent_weak.upgrade() {
                parent.pid.0 as isize
            } else {
                0
            }
        }
        // Test programs are launched by the kernel runner rather than a
        // userspace init process; expose the conventional init parent to keep
        // their POSIX-visible process tree intact.
        None => 1,
    }
}

