pub fn sys_gettimeofday(tv: usize, _tz: usize) -> isize {
    if tv == 0 { return 0; }
    let token = current_user_token();
    let timeval = TimeVal::now();
    let timeval_ptr = tv as *const TimeVal;
    if let Ok(r) = translated_refmut(token, timeval_ptr as *mut TimeVal) {
        *r = timeval;
    } else {
        return EFAULT;
    }
    0
}

