pub fn sys_uname(buf: usize) -> isize {
    #[repr(C)]
    struct UTSName {
        sysname: [u8; 65],
        nodename: [u8; 65],
        release: [u8; 65],
        version: [u8; 65],
        machine: [u8; 65],
        domainname: [u8; 65],
    }
    let token = current_user_token();
    if let Ok(mut buffer) = translated_byte_buffer(token, buf as *const u8, core::mem::size_of::<UTSName>()) {
        use crate::mm::UserBuffer;
        let mut ub = UserBuffer::new(buffer);
        fn pad_to_65(s: &str) -> [u8; 65] {
            let mut arr = [0u8; 65];
            let bytes = s.as_bytes();
            let len = bytes.len().min(64);
            arr[..len].copy_from_slice(&bytes[..len]);
            arr
        }
        let data = UTSName {
            sysname: pad_to_65("Linux"),
            nodename: pad_to_65("hpu"),
            release: pad_to_65("6.1.0-hpu"),
            version: pad_to_65("#1 SMP Thu Jan 1 00:00:00 CST 2026"),
            machine: pad_to_65("riscv64"),
            domainname: pad_to_65("(none)"),
        };
        unsafe {
            let ptr = &data as *const UTSName as *const u8;
            let bytes = core::slice::from_raw_parts(ptr, core::mem::size_of::<UTSName>());
            ub.write(bytes);
        }
        0
    } else {
        EFAULT
    }
}

pub fn sys_times(buf: usize) -> isize {
