            ticks as isize
        }
        Err(err) => err,
    };
    return result;
    // 简化实现
    0
}

pub fn sys_nanosleep(req: usize, rem: usize) -> isize {
    // 简化实现 —— 没有计时器等待时，直接返回
    if req == 0 {
        return EFAULT;
    }
    let token = current_user_token();
    let duration = match translated_refmut(token, req as *mut TimeSpec) {
        Ok(value) => *value,
        Err(err) => return err,
    };
    if duration.nsec >= 1_000_000_000 {
        return EINVAL;
    }
    let deadline = TimeSpec::now() + &duration;
    sleep_current_until(deadline);
    if rem != 0 {
        if let Ok(value) = translated_refmut(token, rem as *mut TimeSpec) {
            *value = TimeSpec::new();
        }
    }
    0
}

