#[inline(always)]
pub fn read_csr<const CSR: usize>() -> usize {
    let value: usize;
    unsafe {
        core::arch::asm!(
            "csrrd {value}, {csr}",
            value = out(reg) value,
            csr = const CSR,
            options(nomem, nostack)
        );
    }
    value
}

#[inline(always)]
pub fn write_csr<const CSR: usize>(value: usize) {
    unsafe {
        core::arch::asm!(
            "csrwr {value}, {csr}",
            value = in(reg) value,
            csr = const CSR,
            options(nomem, nostack)
        );
    }
}

