pub fn init_direct_map() {
    // VSEG=0x9, PLV0 enabled, MAT=1(cacheable), physical base 0.
    // QEMU firmware already sets a working DMW for kernel entry; write it
    // again to keep the setting explicit.
    let dmw0 = (0x9usize << 60) | (1usize << 4) | 1usize;
    write_csr::<CSR_DMW0>(dmw0);
}

pub fn init_page_walk() {
    // 4KiB pages, three 9-bit levels:
    // PTbase=12, PTwidth=9, Dirl_base=21, Dirl_width=9,
    // Dir2_base=30, Dir2_width=9, PTEWidth=0(64-bit PTE).
    let pwcl = 12usize | (9usize << 5) | (21usize << 10) | (9usize << 15) |
        (30usize << 20) | (9usize << 25);
    let pwch = 0usize;
    write_csr::<CSR_PWCL>(pwcl);
    write_csr::<CSR_PWCH>(pwch);
    write_csr::<CSR_STLBPS>(12);
}

pub fn enable_paging() {
    // CRMD.DA=0, CRMD.PG=1.  Kernel addresses live in the 0x9... DMW window;
    // low user addresses are then translated through PGDL.
    let mut crmd = read_csr::<CSR_CRMD>();
    crmd &= !(1usize << 3);
    crmd |= 1usize << 4;
    write_csr::<CSR_CRMD>(crmd);
    invtlb_all();
}

pub fn enable_timer_interrupt() {
    let ecfg = read_csr::<CSR_ECFG>() | (1usize << 11);
    write_csr::<CSR_ECFG>(ecfg);
    let crmd = read_csr::<CSR_CRMD>() | (1usize << 2);
    write_csr::<CSR_CRMD>(crmd);
}

pub fn set_timer_delta(delta: usize) {
    // TCFG: bit0 enable, bit1 periodic, bits[63:2] init value.
    write_csr::<CSR_TCFG>((delta << 2) | 0x1);
}

