pub fn sys_getrandom(buf: usize, len: usize, _flags: usize) -> isize {
    let token = current_user_token();
    let buffers = match translated_byte_buffer(token, buf as *const u8, len) {
        Ok(buffers) => buffers,
        Err(err) => return err,
    };
    let seed = TimeSpec::now().nsec as u8;
    let mut value = seed;
    let mut output = alloc::vec![0u8; len];
    for byte in &mut output {
        value = value.wrapping_mul(33).wrapping_add(17);
        *byte = value;
    }
    UserBuffer::new(buffers).write(&output);
    len as isize
}

pub fn sys_futex(uaddr: usize, operation: u32, value: u32, timeout: usize, _uaddr2: usize, _value3: u32) -> isize {
    const FUTEX_WAIT: u32 = 0;
    const FUTEX_WAKE: u32 = 1;
    const FUTEX_WAIT_BITSET: u32 = 9;
    const FUTEX_WAKE_BITSET: u32 = 10;
    let command = operation & 0x7f;
    match command {
        FUTEX_WAIT | FUTEX_WAIT_BITSET => {
            let token = current_user_token();
            let current = match virt_to_phys(token, uaddr) {
                Some(pa) => unsafe { *(pa as *const u32) },
                None => return EFAULT,
            };
            if current != value {
                return EAGAIN;
            }
            // A full futex implementation needs precise wake queues and
            // timer cancellation.  Returning after one yield keeps libc's
            // lock probes from deadlocking the whole single-core runner.
            suspend_current_and_run_next();
            0
        }
        FUTEX_WAKE | FUTEX_WAKE_BITSET => wake_futex(uaddr, value as usize) as isize,
        _ => 0,
    }
}

pub fn sys_clone(
    flags: u32,
    stack: *const u8,
    ptid: *mut u32,
    tls: usize,
    ctid: *mut u32,
) -> isize {
    let parent = current_task().unwrap();
    if parent.acquire_inner_lock().rlimits[crate::config::RLIMIT_NPROC].0 == 0 {
        return EAGAIN;
    }
    const CLONE_VM: u32 = 0x0000_0100;
    const CLONE_VFORK: u32 = 0x0000_4000;
    const CLONE_CHILD_CLEARTID: u32 = 0x0020_0000;
    let child = if flags & CLONE_VM != 0 && flags & CLONE_VFORK == 0 {
        TaskControlBlock::clone_thread(&parent, stack as usize, tls)
    } else {
        TaskControlBlock::fork(&parent, stack as usize)
    };
    let child_pid = child.pid.0 as u32;
    let token = current_user_token();
    if !ptid.is_null() {
        if let Ok(slot) = translated_refmut(token, ptid) {
            *slot = child_pid;
        } else {
            return EFAULT;
        }
    }
    if !ctid.is_null() {
        if let Ok(slot) = translated_refmut(token, ctid) {
            *slot = child_pid;
        } else {
            return EFAULT;
        }
        if flags & CLONE_CHILD_CLEARTID != 0 {
            child.acquire_inner_lock().clear_child_tid = ctid as usize;
        }
    }
    if let Some(mgr) = crate::fs::manager::FS_MANAGER.lock().as_mut() {
        mgr.fork_process(parent.pid.0, child.pid.0);
    }
    add_task(child);
    child_pid as isize
}

