const SIGKILL: i32 = 9;
const SIGCHLD: i32 = 17;
const SIGSTOP: i32 = 19;
const SIGSET_BYTES: usize = 8;

fn signal_bit(signal: i32) -> Option<u64> {
    if (1..=64).contains(&signal) {
        Some(1u64 << ((signal as usize) - 1))
    } else {
        None
    }
}

fn first_signal(mask: u64) -> i32 {
    mask.trailing_zeros() as i32 + 1
}

fn sanitize_signal_mask(mask: u64) -> u64 {
    mask & !signal_bit(SIGKILL).unwrap() & !signal_bit(SIGSTOP).unwrap()
}

fn read_signal_set(ptr: usize, sigsetsize: usize) -> Result<u64, isize> {
    if ptr == 0 {
        return Err(EFAULT);
    }
    if sigsetsize != 0 && sigsetsize < SIGSET_BYTES {
        return Err(EINVAL);
    }
    let bytes = read_user_bytes(ptr, SIGSET_BYTES)?;
    let mut raw = [0u8; SIGSET_BYTES];
    raw.copy_from_slice(&bytes[..SIGSET_BYTES]);
    Ok(u64::from_ne_bytes(raw))
}

fn write_signal_set(ptr: usize, mask: u64) -> Result<(), isize> {
    if ptr == 0 {
        return Ok(());
    }
    write_user_bytes(ptr, &mask.to_ne_bytes())
}

fn write_signal_info(ptr: usize, signal: i32, child: Option<(usize, u32)>) -> Result<(), isize> {
    if ptr == 0 {
        return Ok(());
    }
    let mut data = [0u8; 128];
    data[0..4].copy_from_slice(&signal.to_ne_bytes());
    match child {
        Some((pid, exit_code)) => {
            data[8..12].copy_from_slice(&(1i32).to_ne_bytes()); // CLD_EXITED
            data[16..20].copy_from_slice(&(pid as i32).to_ne_bytes());
            data[20..24].copy_from_slice(&(0i32).to_ne_bytes());
            data[24..28].copy_from_slice(&((exit_code & 0xff) as i32).to_ne_bytes());
        }
        None => {
            data[8..12].copy_from_slice(&(0i32).to_ne_bytes()); // SI_USER
            let pid = current_task().map(|task| task.pid.0).unwrap_or(0);
            data[16..20].copy_from_slice(&(pid as i32).to_ne_bytes());
        }
    }
    write_user_bytes(ptr, &data)
}

