    if sigsetsize != 0 && sigsetsize < SIGSET_BYTES {
        return EINVAL;
    }
    let task = current_task().unwrap();
    let mut inner = task.acquire_inner_lock();
    if let Err(err) = write_signal_set(oldset, inner.signal_mask) {
        return err;
    }
    if set == 0 {
        return 0;
    }
    let requested = match read_signal_set(set, sigsetsize) {
        Ok(mask) => sanitize_signal_mask(mask),
        Err(err) => return err,
    };
