        0 => inner.signal_mask |= requested,      // SIG_BLOCK
        1 => inner.signal_mask &= !requested,     // SIG_UNBLOCK
        2 => inner.signal_mask = requested,       // SIG_SETMASK
        _ => return EINVAL,
    }
    0
}

