    if sigsetsize != 0 && sigsetsize < SIGSET_BYTES {
        return EINVAL;
    }
    let wanted = match read_signal_set(set, sigsetsize) {
        Ok(mask) => mask,
        Err(err) => return err,
    };
    let duration = if timeout == 0 {
        None
    } else {
        let token = current_user_token();
        match translated_refmut(token, timeout as *mut TimeSpec) {
            Ok(ts) if ts.nsec < 1_000_000_000 => Some(*ts),
            Ok(_) => return EINVAL,
            Err(err) => return err,
        }
    };
    let deadline = duration.map(|ts| TimeSpec::now() + &ts);
    let sigchld_bit = signal_bit(SIGCHLD).unwrap();

    loop {
        let task = current_task().unwrap();
        let ready = {
            let mut inner = task.acquire_inner_lock();
            let child = if wanted & sigchld_bit != 0 {
                inner.children.iter().find_map(|child| {
                    let child_inner = child.acquire_inner_lock();
                    if child_inner.task_status == TaskStatus::Zombie {
                        Some((child.pid.0, child_inner.exit_code))
                    } else {
                        None
                    }
                })
            } else {
                None
            };
            if let Some(child) = child {
                inner.pending_signals &= !sigchld_bit;
                Some((SIGCHLD, Some(child)))
            } else {
                let pending = inner.pending_signals & wanted;
                if pending != 0 {
                    let signal = first_signal(pending);
                    if let Some(bit) = signal_bit(signal) {
                        inner.pending_signals &= !bit;
                    }
                    Some((signal, None))
                } else {
                    None
                }
            }
        };

        if let Some((signal, child)) = ready {
            return match write_signal_info(info, signal, child) {
                Ok(()) => signal as isize,
                Err(err) => err,
            };
        }

        if let Some(end) = deadline {
            if TimeSpec::now() >= end {
                return EAGAIN;
            }
            drop(task);
            sleep_current_until(end);
        } else {
            drop(task);
            block_current_and_run_next();
        }
    }
}

