pub fn start_from_disk() -> bool {
    let Some(base_dir) = detect_basic_dir() else {
        return false;
    };
    let image_root = base_dir.trim_end_matches("/basic").to_string();
    let skip_basic = {
        let marker = format!("{}/skip_basic", image_root);
        let guard = FS_MANAGER.lock();
        guard
            .as_ref()
            .map(|mgr| mgr.path_exists(marker.as_bytes()))
            .unwrap_or(false)
    };
    let mut tests = Vec::new();
    if !skip_basic {
        for &name in BASIC_TESTS {
            tests.push(name.to_string());
        }
    }
    if tests.is_empty() && !skip_basic {
        return false;
    }
    let now = TimeSpec::now();
    {
        let mut runner = RUNNER.lock();
        runner.active = true;
        runner.group_open = !skip_basic;
        runner.image_root = image_root;
        runner.base_dir = base_dir;
        runner.tests = tests;
        runner.next = 0;
        runner.next_group = 0;
        runner.suite_start = now;
    }
    if skip_basic {
        crate::println!("[test-runner] skip basic by image marker");
        crate::println!("#### OS COMP TEST GROUP START basic ####");
        crate::println!("#### OS COMP TEST GROUP END basic ####");
        return spawn_next_group();
    }
    crate::println!("#### OS COMP TEST GROUP START basic ####");
    spawn_next()
}

