        const G = 1 << 6;
        const P = 1 << 7;
        const W = 1 << 8;
        const HUGE = 1 << 12;
        const NR = 1usize << 61;
        const NX = 1usize << 62;

        // Software compatibility flags used by the shared memory manager.
        const R = 1 << 9;
        const X = 1 << 10;
        const U = Self::PLV_USER.bits();
        const A = 1 << 11;
    }
}

#[derive(Copy, Clone)]
pub struct PageTableEntry {
    pub bits: usize,
}

impl PageTableEntry {
    pub fn new(ppn: PhysPageNum, flags: PTEFlags) -> Self {
        let pa = ppn.get_addr().0 & crate::config::PA_MASK;
        let mut hw = PTEFlags::V | PTEFlags::P | PTEFlags::MAT_CC;
        if flags.contains(PTEFlags::U) {
            hw |= PTEFlags::PLV_USER;
        }
        if flags.contains(PTEFlags::W) {
            hw |= PTEFlags::W | PTEFlags::D;
        }
        if !flags.contains(PTEFlags::R) {
            hw |= PTEFlags::NR;
        }
        if !flags.contains(PTEFlags::X) {
            hw |= PTEFlags::NX;
        }
        if flags.contains(PTEFlags::G) {
            hw |= PTEFlags::G;
        }
        let soft = flags & (PTEFlags::R | PTEFlags::X | PTEFlags::A);
        Self { bits: (pa & !0xfff) | hw.bits() | soft.bits() }
    }

    pub fn new_table(ppn: PhysPageNum) -> Self {
        let pa = ppn.get_addr().0 & crate::config::PA_MASK;
        Self { bits: pa & !0xfff }
    }

    pub fn empty() -> Self {
        Self { bits: 0 }
    }

    pub fn ppn(&self) -> PhysPageNum {
        let pa = self.bits & crate::config::PA_MASK & !0xfff;
        PhysPageNum(crate::config::phys_to_virt(pa) / crate::config::PAGE_SIZE)
    }

    pub fn flags(&self) -> PTEFlags {
        PTEFlags::from_bits_truncate(self.bits)
    }

    pub fn is_valid(&self) -> bool {
        self.bits != 0
    }
}

pub struct PageTable {
    root_ppn: PhysPageNum,
    frames: Vec<FrameTracker>,
}

fn vpn_index(vaddr: VirtAddr, level: usize) -> usize {
    (vaddr.0 >> (12 + level * 9)) & 0x1ff
}

fn ppn_to_ptes(ppn: PhysPageNum) -> &'static mut [PageTableEntry] {
    let addr = ppn.0 * crate::config::PAGE_SIZE;
    let va = if (addr & crate::config::DMW_BASE) != 0 {
        addr
    } else {
        crate::config::phys_to_virt(addr)
    };
    unsafe { core::slice::from_raw_parts_mut(va as *mut PageTableEntry, 512) }
}

impl PageTable {
    pub fn new() -> Option<Self> {
        let frame = frame_alloc()?;
        let root_ppn = frame.ppn;
        Some(Self { root_ppn, frames: vec![frame] })
    }

    pub fn empty() -> Self {
        Self { root_ppn: PhysPageNum(0), frames: Vec::new() }
    }

    fn find_pte_create(&mut self, vaddr: VirtAddr) -> &mut PageTableEntry {
        let mut current_ppn = self.root_ppn;
        for level in (0..3).rev() {
            let ptes = ppn_to_ptes(current_ppn);
            let idx = vpn_index(vaddr, level);
            let entry = &mut ptes[idx];
            if level == 0 {
                return entry;
            }
            if !entry.is_valid() {
                let new_frame = frame_alloc().expect("OOM");
                let new_ppn = new_frame.ppn;
                self.frames.push(new_frame);
                *entry = PageTableEntry::new_table(new_ppn);
                current_ppn = new_ppn;
            } else {
                current_ppn = entry.ppn();
            }
        }
        unreachable!()
    }

    pub fn map(&mut self, vaddr: VirtAddr, ppn: PhysPageNum, flags: PTEFlags) {
        let entry = self.find_pte_create(vaddr);
        *entry = PageTableEntry::new(ppn, flags | PTEFlags::V);
    }

    pub fn unmap(&mut self, vaddr: VirtAddr) {
        let entry = self.find_pte_create(vaddr);
        *entry = PageTableEntry::empty();
    }

    pub fn unmap_if_mapped(&mut self, vaddr: VirtAddr) {
        if let Some(entry) = self.find_pte_mut(vaddr) {
            *entry = PageTableEntry::empty();
        }
    }

    pub fn set_flags_if_mapped(&mut self, vaddr: VirtAddr, flags: PTEFlags) -> bool {
        if let Some(entry) = self.find_pte_mut(vaddr) {
            let ppn = entry.ppn();
            *entry = PageTableEntry::new(ppn, flags | PTEFlags::V);
            true
        } else {
            false
        }
    }

    pub fn from_token(token: usize) -> Self {
        let root = crate::config::phys_to_virt(token & crate::config::PA_MASK);
        Self { root_ppn: PhysPageNum(root / crate::config::PAGE_SIZE), frames: Vec::new() }
    }

    pub fn find_pte(&self, vaddr: VirtAddr) -> Option<PageTableEntry> {
        let mut current_ppn = self.root_ppn;
        for level in (0..3).rev() {
            let ptes = ppn_to_ptes(current_ppn);
            let idx = vpn_index(vaddr, level);
            let entry = &ptes[idx];
            if level == 0 {
                return Some(*entry);
            }
            if !entry.is_valid() {
                return None;
            }
            current_ppn = entry.ppn();
        }
        None
    }

    fn find_pte_mut(&mut self, vaddr: VirtAddr) -> Option<&'static mut PageTableEntry> {
        let mut current_ppn = self.root_ppn;
        for level in (0..3).rev() {
            let ptes = ppn_to_ptes(current_ppn);
            let idx = vpn_index(vaddr, level);
            let entry = &mut ptes[idx];
            if level == 0 {
                return if entry.is_valid() { Some(entry) } else { None };
            }
            if !entry.is_valid() {
                return None;
            }
            current_ppn = entry.ppn();
        }
        None
    }

    pub fn token(&self) -> usize {
        self.root_ppn.get_addr().0 & crate::config::PA_MASK
    }
}

