const DMW_BASE: usize = 0x9000_0000_0000_0000;
const UART0: usize = DMW_BASE + 0x1fe0_01e0;
const UART_THR: usize = UART0;
const UART_RBR: usize = UART0;
const UART_LSR: usize = UART0 + 5;
const UART_LSR_DR: u8 = 1 << 0;
const UART_LSR_THRE: u8 = 1 << 5;

const SYSCON_POWEROFF: usize = DMW_BASE + 0x100e_001c;
const POWEROFF_VALUE: u8 = 0x34;

#[inline(always)]
fn mmio_read8(addr: usize) -> u8 {
    unsafe { core::ptr::read_volatile(addr as *const u8) }
}

#[inline(always)]
fn mmio_write8(addr: usize, value: u8) {
    unsafe { core::ptr::write_volatile(addr as *mut u8, value) }
}

pub fn console_getchar() -> Option<char> {
    if (mmio_read8(UART_LSR) & UART_LSR_DR) == 0 {
        None
    } else {
        Some(mmio_read8(UART_RBR) as char)
    }
}

pub fn console_putchar(c: usize) {
    let byte = c as u8;
    if byte == b'\n' {
        console_putchar(b'\r' as usize);
    }
    for _ in 0..100_000 {
        if (mmio_read8(UART_LSR) & UART_LSR_THRE) != 0 {
            break;
        }
    }
    mmio_write8(UART_THR, byte);
}

pub fn shutdown(_failure: bool) -> ! {
    mmio_write8(SYSCON_POWEROFF, POWEROFF_VALUE);
    loop {
        core::hint::spin_loop();
    }
}

pub fn handle_lazy_page_fault(&mut self, fault_va: usize) -> bool {
    let page_va = fault_va & !(crate::config::PAGE_SIZE - 1);
    let flags = match self.areas.iter().find_map(|area| {
        let area_end = area.vaddr + area.pages * crate::config::PAGE_SIZE;
        if page_va >= area.vaddr && page_va < area_end {
            Some(area.flags)
        } else {
            None
        }
    }) {
        Some(flags) => flags,
        None => return false,
    };
    if self.page_table.find_pte(VirtAddr(page_va)).map_or(false, |entry| entry.is_valid()) {
        return false;
    }
    let frame = match frame_alloc() {
        Some(frame) => frame,
        None => return false,
    };
    let ppn = frame.ppn;
    self.frames.push(frame);
    self.page_table.map(VirtAddr(page_va), ppn, flags);
    true
}

